import { LitElement, html, type CSSResultGroup } from 'lit';
import { property } from 'lit/decorators.js';
import { ifDefined } from 'lit/directives/if-defined.js';
import styles from './styles.js';

export type ToggleSwitchSize = 'small' | 'medium' | 'large';

/**
 * uwc-toggleswitch
 *
 * Toggle switch (InputSwitch) component with PrimeNG-level parity.
 *
 * @attr checked  - Whether the switch is on.
 * @attr label    - Label text rendered beside the switch.
 * @attr size     - small | medium | large. Default: medium.
 * @attr disabled - Disable the switch.
 * @attr invalid  - Mark as invalid.
 * @attr name     - Name for form submission.
 *
 * @slot default - Custom label content (overrides label attr).
 *
 * @fires uwc-change - Fired when the switch is toggled. Detail: { checked }.
 *
 * @csspart track - The switch track.
 * @csspart dot   - The sliding thumb.
 * @csspart label - The label element.
 *
 * @cssprop --uwc-switch-width    - Track width. Default: 2.75rem.
 * @cssprop --uwc-switch-height   - Track height. Default: 1.5rem.
 * @cssprop --uwc-switch-bg-off   - Track color when off. Default: #d1d5db.
 * @cssprop --uwc-switch-bg-on    - Track color when on. Default: primary.
 * @cssprop --uwc-switch-radius   - Track border radius. Default: full pill.
 */
export class UwcToggleSwitch extends LitElement {

  static override styles: CSSResultGroup = [styles];

  // ── Core ─────────────────────────────────────────────────────────

  @property({ type: Boolean, reflect: true }) checked  = false;
  @property()                                 label?:   string;
  @property()                                 name?:    string;

  // ── Modifiers ─────────────────────────────────────────────────────

  @property({ reflect: true })                size: ToggleSwitchSize = 'medium';
  @property({ type: Boolean, reflect: true }) disabled = false;
  @property({ type: Boolean, reflect: true }) invalid  = false;

  // ── Handlers ─────────────────────────────────────────────────────

  private _onChange(e: Event) {
    const input = e.target as HTMLInputElement;
    this.checked = input.checked;
    this.dispatchEvent(new CustomEvent('uwc-change', {
      bubbles: true, composed: true,
      detail: { checked: this.checked, originalEvent: e },
    }));
  }

  // ── Render ────────────────────────────────────────────────────────

  override render() {
    const labelContent = this.label
      ? html`<span part="label" class="uwc-ts__label">${this.label}</span>`
      : html`<slot part="label" class="uwc-ts__label"></slot>`;

    return html`
      <label style="display:inline-flex;align-items:center;gap:0.5rem;cursor:${this.disabled ? 'not-allowed' : 'pointer'}">
        <span part="track" class="uwc-ts" role="switch" aria-checked=${this.checked}>
          <input
            type="checkbox"
            .checked=${this.checked}
            name=${ifDefined(this.name)}
            ?disabled=${this.disabled}
            @change=${this._onChange}
          />
          <span part="dot" class="uwc-ts__dot"></span>
        </span>
        ${labelContent}
      </label>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap { 'uwc-toggleswitch': UwcToggleSwitch; }
}
