import { LitElement, html, svg, nothing, type CSSResultGroup, type TemplateResult } from 'lit';
import { property, state } from 'lit/decorators.js';
import { classMap } from 'lit/directives/class-map.js';
import { repeat } from 'lit/directives/repeat.js';
import styles from './styles.js';
import type { SelectOption } from '../types.js';

export type ListboxChangeEventDetail = {
  value: unknown | unknown[];
  originalEvent?: Event;
};

/**
 * uwc-listbox
 *
 * Listbox component with PrimeNG-level parity.
 *
 * @attr options         - JSON array of SelectOption objects.
 * @attr value           - Currently selected value (single) or JSON array (multiple).
 * @attr multiple        - Allow multiple selection (shows checkboxes).
 * @attr filter          - Show a search filter input.
 * @attr filter-placeholder - Placeholder for filter input.
 * @attr filter-by       - Field to filter on. Default: label.
 * @attr list-style-height - Max height of list. Default: 14rem.
 * @attr disabled        - Disable the listbox.
 * @attr invalid         - Mark as invalid.
 * @attr fluid           - Stretch to fill container.
 * @attr empty-message   - Text shown when no options match filter. Default: No results found.
 *
 * @fires uwc-change - Fired on selection change. Detail: { value }.
 * @fires uwc-filter - Fired on filter change. Detail: { query }.
 *
 * @csspart container - The outer wrapper.
 * @csspart list      - The <ul> list element.
 * @csspart item      - Each option <li>.
 *
 * @cssprop --uwc-listbox-radius      - Border radius.
 * @cssprop --uwc-listbox-border      - Border shorthand.
 * @cssprop --uwc-listbox-bg          - Background color.
 * @cssprop --uwc-listbox-item-height - Min item height.
 * @cssprop --uwc-listbox-font-size   - Font size.
 * @cssprop --uwc-listbox-max-height  - List scroll max height. Default: 14rem.
 */
export class UwcListbox extends LitElement {

  static override styles: CSSResultGroup = [styles];

  // ── Data ──────────────────────────────────────────────────────────

  /** Accepts a JSON string or will be set programmatically. */
  @property({ type: Array }) options: SelectOption[] = [];

  /** Single value or array of values (multiple). */
  @property() value: unknown = null;

  // ── Features ──────────────────────────────────────────────────────

  @property({ type: Boolean, reflect: true }) multiple  = false;
  @property({ type: Boolean })               filter    = false;
  @property({ attribute: 'filter-placeholder' }) filterPlaceholder = 'Search...';
  @property({ attribute: 'filter-by' })      filterBy  = 'label';
  @property({ attribute: 'list-style-height' }) listStyleHeight = '';
  @property({ attribute: 'empty-message' })  emptyMessage = 'No results found';

  // ── Modifiers ─────────────────────────────────────────────────────

  @property({ type: Boolean, reflect: true }) disabled = false;
  @property({ type: Boolean, reflect: true }) invalid  = false;
  @property({ type: Boolean, reflect: true }) fluid    = false;

  // ── Internal state ────────────────────────────────────────────────

  @state() private _filterQuery = '';
  @state() private _focusedIdx  = -1;

  // ── Computed ──────────────────────────────────────────────────────

  private get _selectedValues(): unknown[] {
    if (!this.multiple) {
      return this.value != null ? [this.value] : [];
    }
    return Array.isArray(this.value) ? this.value : (this.value != null ? [this.value] : []);
  }

  private get _filteredOptions(): SelectOption[] {
    if (!this._filterQuery) return this.options;
    const q = this._filterQuery.toLowerCase();
    return this.options.filter(opt => {
      if (opt.group) return true; // keep group headers
      const field = (opt as unknown as Record<string, unknown>)[this.filterBy] as string | undefined;
      return String(field ?? opt.label ?? '').toLowerCase().includes(q);
    });
  }

  private _isSelected(opt: SelectOption): boolean {
    return this._selectedValues.some(v => JSON.stringify(v) === JSON.stringify(opt.value));
  }

  // ── Handlers ──────────────────────────────────────────────────────

  private _selectOption(opt: SelectOption, e: Event) {
    if (opt.disabled || opt.group) return;
    let newValue: unknown;
    if (this.multiple) {
      const vals = [...this._selectedValues];
      const idx  = vals.findIndex(v => JSON.stringify(v) === JSON.stringify(opt.value));
      if (idx >= 0) vals.splice(idx, 1); else vals.push(opt.value);
      newValue = vals;
    } else {
      newValue = this._isSelected(opt) ? null : opt.value;
    }
    this.value = newValue;
    this.dispatchEvent(new CustomEvent<ListboxChangeEventDetail>('uwc-change', {
      bubbles: true, composed: true,
      detail: { value: newValue, originalEvent: e },
    }));
  }

  private _onFilter(e: InputEvent) {
    this._filterQuery = (e.target as HTMLInputElement).value;
    this.dispatchEvent(new CustomEvent('uwc-filter', {
      bubbles: true, composed: true,
      detail: { query: this._filterQuery, originalEvent: e },
    }));
  }

  private _onKeydown(e: KeyboardEvent, opt: SelectOption) {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      this._selectOption(opt, e);
    }
  }

  // ── Render helpers ────────────────────────────────────────────────

  private _renderCheckIcon(): TemplateResult {
    return svg`
      <svg width="10" height="10" viewBox="0 0 12 11" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round">
        <polyline points="1 5.5 4.5 9 11 1.5"/>
      </svg>`;
  }

  private _renderItem(opt: SelectOption, idx: number): TemplateResult {
    if (opt.group) {
      return html`<li class="uwc-lb__group-header" role="presentation">${opt.group}</li>`;
    }

    const selected = this._isSelected(opt);
    const classes  = classMap({
      'uwc-lb__item': true,
      'uwc-lb__item--selected':  selected,
      'uwc-lb__item--disabled':  !!opt.disabled,
      'uwc-lb__item--focused':   this._focusedIdx === idx,
    });

    return html`
      <li
        class=${classes}
        role="option"
        aria-selected=${selected}
        tabindex=${opt.disabled ? nothing : '0'}
        @click=${(e: Event) => this._selectOption(opt, e)}
        @keydown=${(e: KeyboardEvent) => this._onKeydown(e, opt)}
      >
        ${this.multiple
          ? html`<span class="uwc-lb__item-cb">${selected ? this._renderCheckIcon() : nothing}</span>`
          : nothing}
        ${opt.icon ? html`<uwc-icon name=${opt.icon} size="15px"></uwc-icon>` : nothing}
        <span class="uwc-lb__item-label">${opt.label}</span>
        ${opt.badge ? html`<span style="margin-inline-start:auto;font-size:0.7em;opacity:0.7">${opt.badge}</span>` : nothing}
        ${!this.multiple && selected
          ? html`<span class="uwc-lb__check">${this._renderCheckIcon()}</span>`
          : nothing}
      </li>
    `;
  }

  // ── Render ────────────────────────────────────────────────────────

  override render() {
    const filtered = this._filteredOptions;
    const listStyle = this.listStyleHeight ? `max-height:${this.listStyleHeight}` : '';

    return html`
      <div part="container" class="uwc-lb">
        ${this.filter ? html`
          <div class="uwc-lb__filter">
            <uwc-icon class="uwc-lb__filter-icon" name="search" size="14px"></uwc-icon>
            <input
              class="uwc-lb__filter-input"
              type="text"
              .value=${this._filterQuery}
              placeholder=${this.filterPlaceholder}
              @input=${this._onFilter}
            />
          </div>` : nothing}

        <ul
          part="list"
          class="uwc-lb__list"
          role="listbox"
          aria-multiselectable=${this.multiple}
          style=${listStyle}
        >
          ${filtered.length === 0
            ? html`<li class="uwc-lb__empty">${this.emptyMessage}</li>`
            : repeat(filtered, (o, i) => `${i}-${String(o.value)}`, (o, i) => this._renderItem(o, i))}
        </ul>
      </div>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap { 'uwc-listbox': UwcListbox; }
}
