import { css } from 'lit';
import { hostReset, floatingPanel, placementOrigins } from '../styles/mixins.js';
import * as t from '../styles/tokens.js';

export default [
  hostReset,
  floatingPanel('.panel', { durationVar: '--uwc-menu-duration', durationDefault: '140ms' }),
  placementOrigins,
  css`
    :host { display: contents; }
    slot[name="trigger"] { display: contents; }

    /* ── Floating panel (visual) ────────────────────────────────────────────── */
    .panel {
      background:    var(--uwc-menu-bg,     ${t.surface});
      border:        var(--uwc-menu-border, 1px solid ${t.border});
      border-radius: var(--uwc-menu-radius, ${t.radiusLg});
      box-shadow:    var(--uwc-menu-shadow, ${t.shadowLg});
      min-width:     var(--uwc-menu-min-width, 180px);
      z-index:       var(--uwc-menu-z, ${t.zFloat});
      overflow:      hidden;
    }

    /* ── List ───────────────────────────────────────────────────────────────── */
    .list { list-style: none; padding: ${t.space1} 0; margin: 0; }

    /* ── Separator ──────────────────────────────────────────────────────────── */
    .separator { height: 1px; background: var(--uwc-menu-separator-color, ${t.borderSubtle}); margin: ${t.space1} 0; }

    /* ── Item ───────────────────────────────────────────────────────────────── */
    .item { position: relative; }

    .item-inner {
      display: flex;
      align-items: center;
      gap: 9px;
      width: 100%;
      padding: ${t.space2} 13px;
      font-size:   var(--uwc-menu-item-font-size, ${t.fontSizeSm});
      font-family: var(--uwc-font-family, inherit);
      color:       var(--uwc-menu-item-color, ${t.text});
      background:  transparent;
      border:      none;
      cursor:      pointer;
      text-align:  left;
      text-decoration: none;
      border-radius: 0;
      outline: none;
      white-space: nowrap;
      transition: background ${t.durationFast}, color ${t.durationFast};
    }
    .item-inner:hover,
    .item-inner:focus-visible {
      background: var(--uwc-menu-item-hover-bg,    ${t.hoverBg});
      color:      var(--uwc-menu-item-hover-color, ${t.text});
    }
    .item--disabled .item-inner {
      color:  var(--uwc-menu-item-disabled-color, ${t.textDisabled});
      cursor: not-allowed;
    }
    .item--disabled .item-inner:hover { background: transparent; }
    .item--active > .item-inner { background: var(--uwc-menu-item-hover-bg, ${t.hoverBg}); }
    .item--danger > .item-inner { color: var(--uwc-menu-item-danger-color, ${t.danger}); }
    .item--danger > .item-inner:hover {
      background: color-mix(in oklab, var(--uwc-menu-item-danger-color, ${t.danger}) 10%, transparent);
      color: var(--uwc-menu-item-danger-color, ${t.danger});
    }

    /* ── Item sub-elements ──────────────────────────────────────────────────── */
    .item-icon {
      width: 18px;
      text-align: center;
      flex-shrink: 0;
      display: flex;
      align-items: center;
      justify-content: center;
    }
    .item-label { flex: 1; }
    .item-badge {
      font-size: ${t.fontSizeXs};
      padding: 1px 6px;
      border-radius: ${t.radiusFull};
      background: ${t.borderSubtle};
      color: ${t.textSecondary};
      font-weight: ${t.fontWeightMedium};
      flex-shrink: 0;
    }
    .item-chevron { font-size: 16px; color: ${t.textMuted}; margin-left: auto; line-height: 1; }

    /* ── Submenu panel ──────────────────────────────────────────────────────── */
    .submenu-panel {
      position: absolute;
      left: calc(100% + 4px);
      top: 0;
      list-style: none;
      padding: ${t.space1} 0;
      margin: 0;
      background:    var(--uwc-menu-bg,     ${t.surface});
      border:        var(--uwc-menu-border, 1px solid ${t.border});
      border-radius: var(--uwc-menu-radius, ${t.radiusLg});
      box-shadow:    var(--uwc-menu-shadow, ${t.shadowLg});
      min-width:     160px;
      z-index: 1;
      animation: submenu-in 120ms ${t.easingStandard} both;
    }

    @keyframes submenu-in {
      from { opacity: 0; transform: translateX(-4px) scale(0.97); }
      to   { opacity: 1; transform: translateX(0) scale(1); }
    }
  `,
];
