import { LitElement, html, type CSSResultGroup } from 'lit';
import { property } from 'lit/decorators.js';
import { ifDefined } from 'lit/directives/if-defined.js';
import styles from './styles.js';

export type RadioButtonVariant = 'outlined' | 'filled';

/**
 * uwc-radiobutton
 *
 * Radio button component with PrimeNG-level parity.
 *
 * @attr checked  - Whether this radio is selected.
 * @attr value    - Value for this option.
 * @attr name     - Group name — radio buttons with same name form a group.
 * @attr label    - Label text rendered beside the radio.
 * @attr disabled - Disable the radio button.
 * @attr invalid  - Mark as invalid (red border).
 * @attr variant  - outlined | filled. Default: outlined.
 *
 * @slot default - Custom label content (overrides label attr).
 *
 * @fires uwc-change - Fired when this radio becomes selected. Detail: { value }.
 *
 * @csspart circle - The visual circle.
 * @csspart label  - The label element.
 *
 * @cssprop --uwc-radio-size        - Circle size. Default: 1.125rem.
 * @cssprop --uwc-radio-bg          - Background color (unchecked).
 * @cssprop --uwc-radio-color       - Accent color for dot and border.
 * @cssprop --uwc-radio-label-color - Label text color.
 * @cssprop --uwc-radio-font-size   - Label font size.
 */
export class UwcRadioButton extends LitElement {

  static override styles: CSSResultGroup = [styles];

  // ── Core ─────────────────────────────────────────────────────────

  @property({ type: Boolean, reflect: true }) checked = false;
  @property()                                 value?:  string;
  @property()                                 name?:   string;
  @property()                                 label?:  string;

  // ── Modifiers ─────────────────────────────────────────────────────

  @property({ type: Boolean, reflect: true }) disabled = false;
  @property({ type: Boolean, reflect: true }) invalid  = false;
  @property({ reflect: true })                variant: RadioButtonVariant = 'outlined';

  // ── Handlers ─────────────────────────────────────────────────────

  private _onChange(e: Event) {
    const input = e.target as HTMLInputElement;
    if (!input.checked) return;
    this.checked = true;
    this.dispatchEvent(new CustomEvent('uwc-change', {
      bubbles: true, composed: true,
      detail: { value: this.value, originalEvent: e },
    }));
  }

  // ── Render ────────────────────────────────────────────────────────

  override render() {
    const labelContent = this.label
      ? html`<span part="label" class="uwc-rb__label">${this.label}</span>`
      : html`<slot part="label" class="uwc-rb__label"></slot>`;

    return html`
      <label style="display:inline-flex;align-items:center;gap:0.5rem;cursor:${this.disabled ? 'not-allowed' : 'pointer'}">
        <span part="circle" class="uwc-rb">
          <input
            type="radio"
            .checked=${this.checked}
            value=${ifDefined(this.value)}
            name=${ifDefined(this.name)}
            ?disabled=${this.disabled}
            @change=${this._onChange}
          />
          <span class="uwc-rb__dot"></span>
        </span>
        ${labelContent}
      </label>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap { 'uwc-radiobutton': UwcRadioButton; }
}
