import {
  LitElement,
  html,
  nothing,
  type TemplateResult,
  type PropertyValues,
} from 'lit';
import styles from './styles.js';
import { property, query, state } from 'lit/decorators.js';
import { classMap }  from 'lit/directives/class-map.js';
import { repeat }    from 'lit/directives/repeat.js';
import { live }      from 'lit/directives/live.js';
import type { Placement } from '../types.js';
import { emit }      from '../utils/dom.utils.js';
import { PlacementController } from '../utils/placement.controller.js';

// ─────────────────────────────────────────────────────────────────────────────
// Types
// ─────────────────────────────────────────────────────────────────────────────

/** How many dates the picker selects per interaction. */
export type DateSelectionMode = 'single' | 'range' | 'multiple';

/** Top-level view shown in the panel. */
export type DatePickerView = 'date' | 'month' | 'year';

/** 12-hour vs 24-hour time display. */
export type HourFormat = '12' | '24';

/** Value type in single mode. */
export type DatePickerSingleValue = Date | null;

/** Value type in range mode — tuple of [start, end | null]. */
export type DatePickerRangeValue = [Date, Date | null] | null;

/** Value type in multiple mode. */
export type DatePickerMultipleValue = Date[];

/** Union of all value types. */
export type DatePickerValue =
  | DatePickerSingleValue
  | DatePickerRangeValue
  | DatePickerMultipleValue;

// ── Event detail shapes ─────────────────────────────────────────────────────

export interface DateSelectEventDetail {
  value:         DatePickerValue;
  selectionMode: DateSelectionMode;
  originalEvent?: Event;
}

export interface DateMonthChangeEventDetail {
  month: number;  // 0–11
  year:  number;
}

export interface DateClearEventDetail {
  previousValue: DatePickerValue;
}

// ── Internal calendar cell ──────────────────────────────────────────────────

interface CalendarCell {
  date:  Date;
  /** True when the cell belongs to a neighbouring month (greyed out). */
  other: boolean;
}

// ─────────────────────────────────────────────────────────────────────────────
// Constants
// ─────────────────────────────────────────────────────────────────────────────

const MONTH_NAMES: readonly string[] = [
  'January', 'February', 'March',     'April',   'May',      'June',
  'July',    'August',   'September', 'October', 'November', 'December',
];

const MONTH_SHORT: readonly string[] = [
  'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun',
  'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec',
];

const DAY_NARROW: readonly string[] = ['Su', 'Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa'];

// ─────────────────────────────────────────────────────────────────────────────
// Pure date utilities
// ─────────────────────────────────────────────────────────────────────────────

/** Strip time — return a new Date at midnight. */
function startOfDay(d: Date): Date {
  return new Date(d.getFullYear(), d.getMonth(), d.getDate());
}

function sameDay(a: Date | null | undefined, b: Date | null | undefined): boolean {
  return Boolean(
    a && b &&
    a.getFullYear() === b.getFullYear() &&
    a.getMonth()    === b.getMonth()    &&
    a.getDate()     === b.getDate(),
  );
}

function isAfter(a: Date, b: Date): boolean  { return startOfDay(a) > startOfDay(b); }
function isBefore(a: Date, b: Date): boolean { return startOfDay(a) < startOfDay(b); }

function isBetween(d: Date, start: Date, end: Date): boolean {
  const sd = startOfDay(d);
  return sd > startOfDay(start) && sd < startOfDay(end);
}

/** ISO-8601 week number (Monday-based). */
function getISOWeek(d: Date): number {
  const date = new Date(d.getTime());
  date.setHours(0, 0, 0, 0);
  date.setDate(date.getDate() + 3 - (date.getDay() + 6) % 7);
  const week1 = new Date(date.getFullYear(), 0, 4);
  return 1 + Math.round(
    ((date.getTime() - week1.getTime()) / 86_400_000 - 3 + (week1.getDay() + 6) % 7) / 7,
  );
}

/**
 * Build a 6×7 grid of CalendarCells for the given month.
 * Pads with cells from adjacent months so the grid is always 42 cells.
 */
function buildCalendarGrid(
  year: number,
  month: number,
  firstDayOfWeek: number,
): CalendarCell[] {
  const firstDay    = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const daysInPrev  = new Date(year, month,     0).getDate();
  const offset      = (firstDay - firstDayOfWeek + 7) % 7;

  const cells: CalendarCell[] = [];

  // Trailing days from previous month
  for (let i = offset - 1; i >= 0; i--) {
    cells.push({ date: new Date(year, month - 1, daysInPrev - i), other: true });
  }
  // Current month
  for (let i = 1; i <= daysInMonth; i++) {
    cells.push({ date: new Date(year, month, i), other: false });
  }
  // Leading days from next month
  let next = 1;
  while (cells.length < 42) {
    cells.push({ date: new Date(year, month + 1, next++), other: true });
  }

  return cells;
}

/** Reorder the 7 day-header abbreviations according to firstDayOfWeek. */
function getOrderedDayHeaders(firstDayOfWeek: number): string[] {
  return Array.from({ length: 7 }, (_, i) => DAY_NARROW[(firstDayOfWeek + i) % 7]);
}

function formatDate(date: Date, fmt: string): string {
  const dd   = String(date.getDate()).padStart(2, '0');
  const mm   = String(date.getMonth() + 1).padStart(2, '0');
  const yyyy = String(date.getFullYear());
  const yy   = yyyy.slice(-2);
  return fmt
    .replace('dd',   dd)
    .replace('mm',   mm)
    .replace('yyyy', yyyy)
    .replace('yy',   yy);
}

function formatTime(
  h: number,
  m: number,
  s: number,
  showSeconds: boolean,
  hourFormat: HourFormat,
  ampm: 'AM' | 'PM',
): string {
  const display12 = hourFormat === '12';
  const hh = display12
    ? String(h === 0 ? 12 : h > 12 ? h - 12 : h).padStart(2, '0')
    : String(h).padStart(2, '0');
  const mm = String(m).padStart(2, '0');
  const ss = String(s).padStart(2, '0');
  const ap = display12 ? ` ${ampm}` : '';
  return showSeconds ? `${hh}:${mm}:${ss}${ap}` : `${hh}:${mm}${ap}`;
}

function isDateDisabled(
  date:          Date,
  minDate:       Date | null,
  maxDate:       Date | null,
  disabledDates: Date[],
  disabledDays:  number[],
): boolean {
  if (minDate && isBefore(date, minDate)) return true;
  if (maxDate && isAfter(date,  maxDate)) return true;
  if (disabledDays.includes(date.getDay())) return true;
  if (disabledDates.some(d => sameDay(d, date))) return true;
  return false;
}

// ─────────────────────────────────────────────────────────────────────────────
// uwc-datepicker
// ─────────────────────────────────────────────────────────────────────────────

/**
 * uwc-datepicker
 *
 * PrimeNG-level date / datetime picker built on PlacementController — the
 * exact same positioning engine used by uwc-overlay, uwc-popover, and friends.
 *
 * Features
 * ─────────
 *  - Single, range, and multiple-date selection modes
 *  - Inline (always-visible) or dropdown mode
 *  - Date + time (12h / 24h, optional seconds)
 *  - Month picker  (`view="month"`) and year picker (`view="year"`)
 *  - Header-click navigation between date → month → year views
 *  - Multi-month display (`number-of-months`)
 *  - ISO-8601 week numbers (`show-week`)
 *  - Configurable first day of week
 *  - min-date / max-date window
 *  - Disabled specific dates (`disabled-dates` JS property)
 *  - Disabled days of the week (`disabled-days` JS property)
 *  - Today / Clear button bar (`show-button-bar`)
 *  - Clear button on input (`show-clear`)
 *  - Keyboard navigation: ↑↓←→ days, PageUp/Down months, Home/End month bounds
 *  - Full ARIA: combobox, dialog, grid, gridcell, aria-selected, aria-disabled
 *  - CSS custom properties for theming
 *
 * Usage — dropdown (default)
 * ──────────────────────────
 * ```html
 * <uwc-datepicker
 *   placeholder="Select date"
 *   date-format="mm/dd/yyyy"
 *   show-clear
 *   show-button-bar>
 * </uwc-datepicker>
 * ```
 *
 * Usage — inline
 * ──────────────
 * ```html
 * <uwc-datepicker inline selection-mode="range"></uwc-datepicker>
 * ```
 *
 * Value access
 * ────────────
 * ```ts
 * const dp = document.querySelector<UwcDatepicker>('uwc-datepicker');
 * dp.value = new Date();                             // single
 * dp.value = [new Date(), null];                     // range — start only
 * dp.value = [new Date('2025-01-01'), new Date()];   // range — complete
 * dp.value = [new Date('2025-01-10'), new Date('2025-01-20')]; // multiple
 * ```
 *
 * @fires uwc-date-select   — { value, selectionMode, originalEvent? }
 * @fires uwc-month-change  — { month: 0–11, year }
 * @fires uwc-clear         — { previousValue }
 * @fires uwc-show
 * @fires uwc-hide
 * @fires uwc-focus
 * @fires uwc-blur
 *
 * @attr selection-mode     — single | range | multiple.  Default: single
 * @attr date-format        — Format string: mm/dd/yyyy dd/mm/yyyy yyyy-mm-dd dd.mm.yyyy etc.  Default: mm/dd/yyyy
 * @attr view               — date | month | year (starting view).  Default: date
 * @attr placement          — Any Placement value.  Default: bottom-start
 * @attr offset             — Gap px between trigger and panel.  Default: 4
 * @attr placeholder        — Input placeholder text
 * @attr inline             — Renders calendar always-visible; no input trigger
 * @attr show-clear         — Show × button on the input
 * @attr show-button-bar    — Show Today / Clear action bar at panel bottom
 * @attr show-time          — Append a time spinner below the calendar
 * @attr hour-format        — 12 | 24.  Default: 24
 * @attr show-seconds       — Show seconds column in time spinner
 * @attr show-week          — Show ISO-8601 week-number column
 * @attr number-of-months   — How many month panels to show side-by-side.  Default: 1
 * @attr first-day-of-week  — 0=Sun … 6=Sat.  Default: 0
 * @attr min-date           — Earliest selectable date (JS property only)
 * @attr max-date           — Latest selectable date  (JS property only)
 * @attr disabled-dates     — Date[] of individually disabled dates (JS property only)
 * @attr disabled-days      — number[] of disabled weekday indices (JS property only)
 * @attr readonly           — Input is read-only; calendar cannot be opened
 * @attr disabled           — Full component disabled
 * @attr trigger-id         — ID of an external trigger element (deep shadow-DOM traversal)
 *
 * @csspart trigger         — The input wrapper div
 * @csspart input           — The text input element
 * @csspart clear-btn       — The × clear button inside the trigger
 * @csspart cal-icon        — The calendar icon button inside the trigger
 * @csspart panel           — The floating calendar panel
 * @csspart header          — Month-panel header row
 * @csspart nav-btn         — Previous / next navigation buttons
 * @csspart day-name        — Day-of-week column headers
 * @csspart week-num        — ISO week-number cells
 * @csspart day             — Individual day cells
 * @csspart day-today       — Today's cell
 * @csspart day-selected    — Selected day cell(s)
 * @csspart day-in-range    — Cells inside a range
 * @csspart day-disabled    — Disabled cells
 * @csspart month-cell      — Cells in the month grid view
 * @csspart year-cell       — Cells in the year grid view
 * @csspart time-section    — Time-picker wrapper
 * @csspart button-bar      — Today / Clear bar
 *
 * @cssprop --uwc-dp-primary          Accent colour.  Default: #c07a18
 * @cssprop --uwc-dp-bg               Panel background.  Default: #fff
 * @cssprop --uwc-dp-border           Panel border.  Default: 1px solid rgba(0,0,0,0.09)
 * @cssprop --uwc-dp-radius           Panel border-radius.  Default: 12px
 * @cssprop --uwc-dp-shadow           Panel box-shadow
 * @cssprop --uwc-dp-z                Panel z-index.  Default: 9999
 * @cssprop --uwc-dp-duration         Open/close transition.  Default: 160ms
 * @cssprop --uwc-dp-trigger-bg       Input background.  Default: #fff
 * @cssprop --uwc-dp-trigger-border   Input border.  Default: 1px solid #d0cfc9
 * @cssprop --uwc-dp-trigger-radius   Input border-radius.  Default: 8px
 * @cssprop --uwc-dp-trigger-color    Input text colour.  Default: #111
 * @cssprop --uwc-dp-hover-bg         Day cell hover background
 * @cssprop --uwc-dp-range-bg         In-range cell background
 * @cssprop --uwc-dp-header-color     Month/year label colour.  Default: #111
 * @cssprop --uwc-dp-day-color        Day cell text colour.  Default: #222
 */
export class UwcDatepicker extends LitElement {

  // ── Public properties ─────────────────────────────────────────────────────

  @property({ attribute: false })
  value: DatePickerValue = null;

  @property({ type: String, attribute: 'selection-mode' })
  selectionMode: DateSelectionMode = 'single';

  @property({ type: String, attribute: 'date-format' })
  dateFormat = 'mm/dd/yyyy';

  /** Earliest selectable date — set as a JS property. */
  @property({ attribute: false })
  minDate: Date | null = null;

  /** Latest selectable date — set as a JS property. */
  @property({ attribute: false })
  maxDate: Date | null = null;

  /** Individually disabled dates — set as a JS property. */
  @property({ attribute: false })
  disabledDates: Date[] = [];

  /** Weekday indices to disable: 0=Sun … 6=Sat — set as a JS property. */
  @property({ attribute: false })
  disabledDays: number[] = [];

  @property({ type: Boolean, attribute: 'show-time' })
  showTime = false;

  @property({ type: String, attribute: 'hour-format' })
  hourFormat: HourFormat = '24';

  @property({ type: Boolean, attribute: 'show-seconds' })
  showSeconds = false;

  @property({ type: Boolean, attribute: 'show-week' })
  showWeek = false;

  @property({ type: Number, attribute: 'number-of-months' })
  numberOfMonths = 1;

  @property({ type: Number, attribute: 'first-day-of-week' })
  firstDayOfWeek = 0;

  @property({ type: Boolean, reflect: true })
  inline = false;

  @property({ type: Boolean, attribute: 'show-button-bar' })
  showButtonBar = false;

  @property({ type: Boolean, attribute: 'show-clear' })
  showClear = false;

  @property({ type: String })
  placeholder = 'Select date';

  @property({ type: Boolean, reflect: true })
  readonly = false;

  @property({ type: Boolean, reflect: true })
  disabled = false;

  @property({ type: String })
  view: DatePickerView = 'date';

  @property({ type: String })
  placement: Placement = 'bottom-start';

  @property({ type: Number })
  offset = 4;

  @property({ type: String, attribute: 'trigger-id' })
  triggerId?: string;

  // ── Internal reactive state ───────────────────────────────────────────────

  /** The month/year currently shown in the panel (always set to 1st of month). */
  @state() private _viewDate: Date = (() => {
    const now = new Date();
    return new Date(now.getFullYear(), now.getMonth(), 1);
  })();

  /** Which sub-view is displayed inside the panel. */
  @state() private _currentView: DatePickerView = 'date';

  /** First click in range mode before the range is committed. */
  @state() private _rangeStart: Date | null = null;

  /** The day cell the mouse is currently hovering over (range preview). */
  @state() private _hoveredDate: Date | null = null;

  /** Formatted string shown in the text input. */
  @state() private _inputValue = '';

  /** Time spinner state. */
  @state() private _timeH = 0;
  @state() private _timeM = 0;
  @state() private _timeS = 0;
  @state() private _ampm: 'AM' | 'PM' = 'AM';

  /** Base year for the decade grid (always a multiple of 12). */
  @state() private _yearBase: number = (() =>
    Math.floor(new Date().getFullYear() / 12) * 12
  )();

  /** Focused cell for keyboard navigation. */
  @state() private _focusedDate: Date | null = null;

  // ── Element queries ───────────────────────────────────────────────────────

  @query('#trigger-input') private _triggerInput!: HTMLInputElement;
  @query('#panel')         private _panel!:        HTMLElement;

  // ── PlacementController ───────────────────────────────────────────────────
  //
  // Datepicker renders its own <input> trigger, so we call
  // setTriggerElement() in firstUpdated() — the same pattern as uwc-dropdown.

  private readonly _pc = new PlacementController(this, {
    getPanelEl: () => this._panel,

    onTriggerFound: (el: HTMLElement) => {
      const onKeydown = (e: KeyboardEvent): void => {
        if (this.disabled || this.readonly) return;
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault();
          this._pc.toggle();
        }
      };
      el.addEventListener('keydown', onKeydown);
      return () => el.removeEventListener('keydown', onKeydown);
    },

    dismissOnOutsideClick: true,
    dismissOnEscape:       true,

    afterShow: () => {
      // Open the panel on the month of the first selected date
      const first = this._firstSelectedDate();
      if (first) {
        this._viewDate = new Date(first.getFullYear(), first.getMonth(), 1);
      }
      // Honour the `view` attribute as the starting view
      this._currentView = this.view;
      emit(this, 'uwc-show');
    },

    afterHide: () => {
      // Reset transient state on close so the panel is clean on re-open
      this._hoveredDate = null;
      this._rangeStart  = null;
      emit(this, 'uwc-hide');
    },
  });

  // ── Lifecycle ─────────────────────────────────────────────────────────────

  override firstUpdated(): void {
    if (!this.inline) {
      // Datepicker renders its own trigger input — bypass slot/trigger-id wiring.
      // setTriggerElement() wires the onTriggerFound callback (keyboard handler)
      // and sets this._pc.triggerEl so position() can measure against it.
      this._pc.firstUpdated(
        this.triggerId ?? null,
        null, // no trigger slot — we use the rendered input directly
      );
      if (!this.triggerId) {
        this._pc.setTriggerElement(this._triggerInput);
      }
    }

    this._syncInputValue();
  }

  protected override updated(changed: PropertyValues): void {
    super.updated(changed);

    if (!this.inline) {
      this._pc.updated(
        changed as Map<PropertyKey, unknown>,
        this.triggerId ?? null,
        null,
      );
    }

    if (changed.has('value')) {
      this._syncInputValue();
    }

    if (changed.has('view')) {
      this._currentView = this.view;
    }
  }

  // ── Value helpers ─────────────────────────────────────────────────────────

  private _firstSelectedDate(): Date | null {
    if (!this.value) return null;
    if (Array.isArray(this.value)) return this.value[0] ?? null;
    return this.value as Date;
  }

  private _hasValue(): boolean {
    const v = this.value;
    if (!v) return false;
    if (Array.isArray(v)) return v.length > 0 && v[0] !== null;
    return true;
  }

  private _syncInputValue(): void {
    const v = this.value;
    if (!v || (Array.isArray(v) && v.length === 0)) {
      this._inputValue = '';
      return;
    }

    switch (this.selectionMode) {
      case 'single': {
        this._inputValue = this._formatFull(v as Date);
        break;
      }
      case 'range': {
        const [s, e] = v as [Date, Date | null];
        this._inputValue = s
          ? `${this._formatFull(s)} → ${e ? this._formatFull(e) : '–'}`
          : '';
        break;
      }
      case 'multiple': {
        const dates = v as Date[];
        if (dates.length === 0)      this._inputValue = '';
        else if (dates.length === 1) this._inputValue = this._formatFull(dates[0]);
        else                          this._inputValue = `${dates.length} dates selected`;
        break;
      }
    }
  }

  /** Format a Date using dateFormat + optional time suffix. */
  private _formatFull(date: Date): string {
    let s = formatDate(date, this.dateFormat);
    if (this.showTime) {
      s += ' ' + formatTime(this._timeH, this._timeM, this._timeS,
                            this.showSeconds, this.hourFormat, this._ampm);
    }
    return s;
  }

  // ── Day-cell state queries ────────────────────────────────────────────────

  private _isSelected(date: Date): boolean {
    const v = this.value;
    if (!v) return false;
    if (this.selectionMode === 'single')   return sameDay(v as Date, date);
    if (this.selectionMode === 'multiple') return (v as Date[]).some(d => sameDay(d, date));
    if (this.selectionMode === 'range') {
      const [s, e] = v as [Date, Date | null];
      return sameDay(s, date) || (e !== null && sameDay(e, date));
    }
    return false;
  }

  private _isRangeStart(date: Date): boolean {
    if (this.selectionMode !== 'range') return false;
    const s = Array.isArray(this.value)
      ? (this.value as [Date, Date | null])[0]
      : this._rangeStart;
    return s !== null && s !== undefined && sameDay(s, date);
  }

  private _isRangeEnd(date: Date): boolean {
    if (this.selectionMode !== 'range' || !Array.isArray(this.value)) return false;
    const e = (this.value as [Date, Date | null])[1];
    return e !== null && sameDay(e, date);
  }

  private _isInRange(date: Date): boolean {
    if (this.selectionMode !== 'range') return false;

    // Committed range
    if (Array.isArray(this.value)) {
      const [s, e] = this.value as [Date, Date | null];
      if (s && e) return isBetween(date, s, e);
    }

    // Hover preview (one end committed, other end is the hovered cell)
    if (this._rangeStart && this._hoveredDate) {
      const start = isBefore(this._rangeStart, this._hoveredDate) ? this._rangeStart : this._hoveredDate;
      const end   = isBefore(this._rangeStart, this._hoveredDate) ? this._hoveredDate : this._rangeStart;
      return isBetween(date, start, end);
    }

    return false;
  }

  private _isToday(date: Date): boolean {
    return sameDay(date, new Date());
  }

  private _isDisabled(date: Date): boolean {
    return isDateDisabled(date, this.minDate, this.maxDate, this.disabledDates, this.disabledDays);
  }

  // ── Selection logic ───────────────────────────────────────────────────────

  private _selectDate(date: Date, originalEvent?: Event): void {
    if (this.disabled || this.readonly) return;
    if (this._isDisabled(date)) return;

    // Stamp the current time onto the selected date when showTime is on
    let d = new Date(date);
    if (this.showTime) {
      const h = this.hourFormat === '12'
        ? (this._ampm === 'PM'
            ? (this._timeH === 12 ? 12 : this._timeH + 12)
            : (this._timeH === 12 ? 0  : this._timeH))
        : this._timeH;
      d.setHours(h, this._timeM, this._timeS, 0);
    }

    switch (this.selectionMode) {
      case 'single': {
        // Toggle off if same date is clicked again
        this.value = sameDay(this.value as Date | null, d) ? null : d;
        if (this.value && !this.inline) this._pc.hide();
        break;
      }
      case 'multiple': {
        const arr = Array.isArray(this.value) ? [...(this.value as Date[])] : [];
        const idx = arr.findIndex(x => sameDay(x, d));
        if (idx >= 0) arr.splice(idx, 1); else arr.push(d);
        this.value = arr;
        break;
      }
      case 'range': {
        if (!this._rangeStart) {
          // First click — anchor the start, expose a partial value
          this._rangeStart = d;
          this.value = [d, null];
        } else {
          // Second click — commit the full range (always start < end)
          const s = isBefore(this._rangeStart, d) ? this._rangeStart : d;
          const e = isBefore(this._rangeStart, d) ? d : this._rangeStart;
          this.value       = [s, e];
          this._rangeStart = null;
          if (!this.inline) this._pc.hide();
        }
        break;
      }
    }

    emit<DateSelectEventDetail>(this, 'uwc-date-select', {
      value:         this.value,
      selectionMode: this.selectionMode,
      originalEvent,
    });
  }

  // ── Month / Year selection ────────────────────────────────────────────────

  private _selectMonth(month: number): void {
    const year = this._viewDate.getFullYear();
    this._viewDate = new Date(year, month, 1);

    if (this.view === 'month') {
      // In month-picker mode — commit value directly
      this.value = new Date(year, month, 1);
      if (!this.inline) this._pc.hide();
      emit<DateSelectEventDetail>(this, 'uwc-date-select', {
        value: this.value, selectionMode: this.selectionMode,
      });
    } else {
      // In date-picker mode — drill back to date view
      this._currentView = 'date';
    }

    emit<DateMonthChangeEventDetail>(this, 'uwc-month-change', { month, year });
  }

  private _selectYear(year: number): void {
    this._yearBase = Math.floor(year / 12) * 12;
    this._viewDate = new Date(year, this._viewDate.getMonth(), 1);

    if (this.view === 'year') {
      this.value = new Date(year, 0, 1);
      if (!this.inline) this._pc.hide();
      emit<DateSelectEventDetail>(this, 'uwc-date-select', {
        value: this.value, selectionMode: this.selectionMode,
      });
    } else {
      // Drill down to month view
      this._currentView = 'month';
    }
  }

  // ── Navigation ────────────────────────────────────────────────────────────

  private _prevMonth(step = 1): void {
    const d = this._viewDate;
    this._viewDate = new Date(d.getFullYear(), d.getMonth() - step, 1);
    emit<DateMonthChangeEventDetail>(this, 'uwc-month-change', {
      month: this._viewDate.getMonth(),
      year:  this._viewDate.getFullYear(),
    });
  }

  private _nextMonth(step = 1): void {
    const d = this._viewDate;
    this._viewDate = new Date(d.getFullYear(), d.getMonth() + step, 1);
    emit<DateMonthChangeEventDetail>(this, 'uwc-month-change', {
      month: this._viewDate.getMonth(),
      year:  this._viewDate.getFullYear(),
    });
  }

  private _prevYear(): void {
    this._viewDate = new Date(this._viewDate.getFullYear() - 1, this._viewDate.getMonth(), 1);
  }

  private _nextYear(): void {
    this._viewDate = new Date(this._viewDate.getFullYear() + 1, this._viewDate.getMonth(), 1);
  }

  private _prevDecade(): void { this._yearBase -= 12; }
  private _nextDecade(): void { this._yearBase += 12; }

  // ── Time spinner ──────────────────────────────────────────────────────────

  private _stepTime(field: 'h' | 'm' | 's', delta: 1 | -1): void {
    if (field === 'h') {
      const max = this.hourFormat === '12' ? 12 : 23;
      const min = this.hourFormat === '12' ? 1  : 0;
      let v = this._timeH + delta;
      if (v > max) v = min;
      if (v < min) v = max;
      this._timeH = v;
    } else if (field === 'm') {
      let v = this._timeM + delta;
      if (v > 59) v = 0; if (v < 0) v = 59;
      this._timeM = v;
    } else {
      let v = this._timeS + delta;
      if (v > 59) v = 0; if (v < 0) v = 59;
      this._timeS = v;
    }
    this._syncInputValue();
  }

  private _setTimeField(field: 'h' | 'm' | 's', raw: string): void {
    const max12h = { h: 12, m: 59, s: 59 };
    const max24h = { h: 23, m: 59, s: 59 };
    const max    = (this.hourFormat === '12' ? max12h : max24h)[field];
    const min    = (field === 'h' && this.hourFormat === '12') ? 1 : 0;
    let v = parseInt(raw, 10);
    if (isNaN(v) || v < min) v = min;
    if (v > max) v = max;
    if (field === 'h') this._timeH = v;
    else if (field === 'm') this._timeM = v;
    else this._timeS = v;
    this._syncInputValue();
  }

  private _toggleAmPm(): void {
    this._ampm = this._ampm === 'AM' ? 'PM' : 'AM';
    this._syncInputValue();
  }

  // ── Keyboard navigation ───────────────────────────────────────────────────

  private _handleCalendarKeydown(e: KeyboardEvent): void {
    if (this._currentView !== 'date') return;

    const base = this._focusedDate ?? this._firstSelectedDate() ?? new Date();
    let   next = new Date(base);

    switch (e.key) {
      case 'ArrowRight': next.setDate(next.getDate() + 1); break;
      case 'ArrowLeft':  next.setDate(next.getDate() - 1); break;
      case 'ArrowDown':  next.setDate(next.getDate() + 7); break;
      case 'ArrowUp':    next.setDate(next.getDate() - 7); break;
      case 'PageDown':   next.setMonth(next.getMonth() + 1); break;
      case 'PageUp':     next.setMonth(next.getMonth() - 1); break;
      case 'Home':
        next = new Date(next.getFullYear(), next.getMonth(), 1);
        break;
      case 'End':
        next = new Date(next.getFullYear(), next.getMonth() + 1, 0);
        break;
      case 'Enter':
        e.preventDefault();
        if (this._focusedDate) this._selectDate(this._focusedDate, e);
        return;
      default:
        return;
    }

    e.preventDefault();
    this._focusedDate = next;

    // Auto-advance view when keyboard focus crosses a month boundary
    const vd = this._viewDate;
    if (next.getMonth() !== vd.getMonth() || next.getFullYear() !== vd.getFullYear()) {
      this._viewDate = new Date(next.getFullYear(), next.getMonth(), 1);
    }
  }

  // ── Clear / Today actions ─────────────────────────────────────────────────

  private _clear(e?: Event): void {
    e?.stopPropagation();
    const prev    = this.value;
    this.value       = this.selectionMode === 'multiple' ? [] : null;
    this._rangeStart = null;
    this._inputValue = '';
    emit<DateClearEventDetail>(this, 'uwc-clear', { previousValue: prev });
    emit<DateSelectEventDetail>(this, 'uwc-date-select', {
      value: this.value, selectionMode: this.selectionMode,
    });
  }

  private _goToday(): void {
    const today = new Date();
    this._viewDate = new Date(today.getFullYear(), today.getMonth(), 1);
    this._selectDate(today);
  }

  // ── Public imperative API ─────────────────────────────────────────────────

  /** Open the calendar panel programmatically. No-op in inline mode. */
  public show(): void   { if (!this.inline) this._pc.show(); }

  /** Close the calendar panel programmatically. No-op in inline mode. */
  public hide(): void   { if (!this.inline) this._pc.hide(); }

  /** Toggle the calendar panel. No-op in inline mode. */
  public toggle(): void { if (!this.inline) this._pc.toggle(); }

  /** Clear the current value. */
  public clear(): void  { this._clear(); }

  /** Whether the panel is currently open. Always true in inline mode. */
  public get isOpen(): boolean { return this.inline ? true : this._pc.open; }

  // ═══════════════════════════════════════════════════════════════════════════
  // RENDER
  // ═══════════════════════════════════════════════════════════════════════════

  protected override render(): TemplateResult {
    return this.inline ? this._renderInline() : this._renderDropdown();
  }

  // ── Dropdown wrapper (input trigger + positioned panel) ───────────────────

  private _renderDropdown(): TemplateResult {
    const open     = this._pc.open;
    const hasValue = this._hasValue();

    return html`
      <div
        part="trigger"
        class=${classMap({
          'dp-trigger':           true,
          'dp-trigger--open':     open,
          'dp-trigger--disabled': this.disabled,
          'dp-trigger--readonly': this.readonly,
        })}
      >
        <input
          id="trigger-input"
          part="input"
          type="text"
          class="dp-input"
          .value=${live(this._inputValue)}
          placeholder=${this.placeholder}
          ?readonly=${true}
          ?disabled=${this.disabled}
          autocomplete="off"
          aria-haspopup="dialog"
          aria-expanded=${open}
          aria-label=${this._inputValue || this.placeholder}
          @click=${(e: Event) => {
            e.stopPropagation();
            if (!this.disabled && !this.readonly) this._pc.toggle();
          }}
          @focus=${() => emit(this, 'uwc-focus')}
          @blur=${ () => emit(this, 'uwc-blur')}
        />

        ${hasValue && this.showClear ? html`
          <button
            part="clear-btn"
            class="dp-clear-btn"
            type="button"
            tabindex="-1"
            aria-label="Clear"
            @click=${this._clear}
          >✕</button>
        ` : nothing}

        <button
          part="cal-icon"
          class="dp-cal-icon"
          type="button"
          tabindex="-1"
          aria-hidden="true"
          ?disabled=${this.disabled}
          @click=${(e: Event) => {
            e.stopPropagation();
            if (!this.disabled && !this.readonly) this._pc.toggle();
          }}
        >
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none" aria-hidden="true">
            <rect x="1" y="3" width="14" height="12" rx="2" stroke="currentColor" stroke-width="1.25" fill="none"/>
            <path d="M1 7h14" stroke="currentColor" stroke-width="1.25"/>
            <path d="M5 1v4M11 1v4" stroke="currentColor" stroke-width="1.25" stroke-linecap="round"/>
          </svg>
        </button>
      </div>

      <div
        id="panel"
        part="panel"
        popover="manual"
        role="dialog"
        aria-label="Calendar"
        aria-modal="true"
        class=${classMap({
          'dp-panel':    true,
          'is-open':     open,
        })}
        data-placement=${this.placement}
        @keydown=${this._handleCalendarKeydown.bind(this)}
      >
        ${this._renderPanelContent()}
      </div>
    `;
  }

  // ── Inline wrapper (no input, always visible) ─────────────────────────────

  private _renderInline(): TemplateResult {
    return html`
      <div
        class="dp-panel dp-panel--inline"
        role="dialog"
        aria-label="Calendar"
        @keydown=${this._handleCalendarKeydown.bind(this)}
      >
        ${this._renderPanelContent()}
      </div>
    `;
  }

  // ── Panel content router ──────────────────────────────────────────────────

  private _renderPanelContent(): TemplateResult {
    switch (this._currentView) {
      case 'year':  return this._renderYearGrid();
      case 'month': return this._renderMonthGrid();
      default:      return this._renderDateView();
    }
  }

  // ── Date view ─────────────────────────────────────────────────────────────

  private _renderDateView(): TemplateResult {
    const n       = Math.max(1, this.numberOfMonths);
    const panels  = Array.from({ length: n }, (_, i) => {
      const d = new Date(this._viewDate.getFullYear(), this._viewDate.getMonth() + i, 1);
      return { year: d.getFullYear(), month: d.getMonth() };
    });

    return html`
      <div class="dp-date-view" style="--dp-months: ${n}">
        ${panels.map((p, i) => this._renderMonthPanel(p.year, p.month, i, n))}
      </div>
      ${this.showTime        ? this._renderTimePicker()  : nothing}
      ${this.showButtonBar   ? this._renderButtonBar()   : nothing}
    `;
  }

  private _renderMonthPanel(
    year:  number,
    month: number,
    idx:   number,
    total: number,
  ): TemplateResult {
    const cells   = buildCalendarGrid(year, month, this.firstDayOfWeek);
    const headers = getOrderedDayHeaders(this.firstDayOfWeek);
    const isFirst = idx === 0;
    const isLast  = idx === total - 1;

    return html`
      <div class="dp-month-panel">

        <!-- ── Header ── -->
        <div part="header" class="dp-header">
          ${isFirst ? html`
            <button
              part="nav-btn"
              class="dp-nav-btn"
              type="button"
              aria-label="Previous month"
              @click=${() => this._prevMonth(total)}
            >‹</button>
          ` : html`<span class="dp-nav-spacer"></span>`}

          <div class="dp-header-labels">
            <button
              class="dp-month-label"
              type="button"
              title="Select month"
              @click=${() => {
                if (this.view === 'date') this._currentView = 'month';
              }}
            >${MONTH_NAMES[month]}</button>

            <button
              class="dp-year-label"
              type="button"
              title="Select year"
              @click=${() => {
                if (this.view !== 'year') {
                  this._yearBase    = Math.floor(year / 12) * 12;
                  this._currentView = 'year';
                }
              }}
            >${year}</button>
          </div>

          ${isLast ? html`
            <button
              part="nav-btn"
              class="dp-nav-btn"
              type="button"
              aria-label="Next month"
              @click=${() => this._nextMonth(total)}
            >›</button>
          ` : html`<span class="dp-nav-spacer"></span>`}
        </div>

        <!-- ── Day-name column headers ── -->
        <div
          class=${classMap({
            'dp-day-headers': true,
            'dp-day-headers--week': this.showWeek,
          })}
          aria-hidden="true"
        >
          ${this.showWeek ? html`<span class="dp-week-label">W</span>` : nothing}
          ${headers.map(d => html`<span part="day-name" class="dp-day-name">${d}</span>`)}
        </div>

        <!-- ── Day grid ── -->
        <div
          class=${classMap({
            'dp-days-grid':      true,
            'dp-days-grid--week': this.showWeek,
          })}
          role="grid"
          aria-label="${MONTH_NAMES[month]} ${year}"
        >
          ${repeat(
            Array.from({ length: 6 }, (_, r) => r),
            r => r,
            r => {
              const row    = cells.slice(r * 7, r * 7 + 7);
              const wkNum  = this.showWeek ? getISOWeek(row[0].date) : null;
              return html`
                ${this.showWeek
                  ? html`<span part="week-num" class="dp-week-num" aria-label="Week ${wkNum}">${wkNum}</span>`
                  : nothing
                }
                ${row.map(({ date, other }) => this._renderDayCell(date, other))}
              `;
            },
          )}
        </div>

      </div>
    `;
  }

  private _renderDayCell(date: Date, other: boolean): TemplateResult {
    const disabled  = this._isDisabled(date);
    const selected  = this._isSelected(date);
    const rangeS    = this._isRangeStart(date);
    const rangeE    = this._isRangeEnd(date);
    const inRange   = this._isInRange(date);
    const today     = this._isToday(date);
    const focused   = this._focusedDate !== null && sameDay(this._focusedDate, date);

    return html`
      <button
        type="button"
        part=${[
          'day',
          today    && 'day-today',
          selected && 'day-selected',
          inRange  && 'day-in-range',
          disabled && 'day-disabled',
        ].filter(Boolean).join(' ')}
        class=${classMap({
          'dp-day':           true,
          'dp-day--other':    other,
          'dp-day--today':    today,
          'dp-day--selected': selected,
          'dp-day--range-s':  rangeS && !rangeE,
          'dp-day--range-e':  rangeE,
          'dp-day--in-range': inRange,
          'dp-day--disabled': disabled,
          'dp-day--focused':  focused,
        })}
        ?disabled=${disabled}
        role="gridcell"
        aria-label=${date.toDateString()}
        aria-selected=${selected}
        aria-disabled=${disabled}
        tabindex=${focused ? '0' : '-1'}
        @click=${(e: Event) => this._selectDate(date, e)}
        @mouseenter=${() => { this._hoveredDate = date; }}
        @mouseleave=${() => { this._hoveredDate = null; }}
      >${date.getDate()}</button>
    `;
  }

  // ── Month grid view ───────────────────────────────────────────────────────

  private _renderMonthGrid(): TemplateResult {
    const year   = this._viewDate.getFullYear();
    const selM   = this._firstSelectedDate()?.getMonth()    ?? -1;
    const selY   = this._firstSelectedDate()?.getFullYear() ?? -1;
    const todayM = new Date().getMonth();
    const todayY = new Date().getFullYear();

    return html`
      <div class="dp-view-panel">
        <div part="header" class="dp-header">
          <button part="nav-btn" class="dp-nav-btn" type="button" aria-label="Previous year"
            @click=${this._prevYear.bind(this)}>‹</button>
          <button class="dp-year-label" type="button"
            @click=${() => { this._yearBase = Math.floor(year / 12) * 12; this._currentView = 'year'; }}
          >${year}</button>
          <button part="nav-btn" class="dp-nav-btn" type="button" aria-label="Next year"
            @click=${this._nextYear.bind(this)}>›</button>
        </div>

        <div class="dp-month-grid">
          ${MONTH_SHORT.map((name, i) => html`
            <button
              type="button"
              part=${['month-cell', (i === selM && year === selY) && 'month-cell--selected'].filter(Boolean).join(' ')}
              class=${classMap({
                'dp-month-cell':           true,
                'dp-month-cell--selected': i === selM && year === selY,
                'dp-month-cell--today':    i === todayM && year === todayY,
              })}
              @click=${() => this._selectMonth(i)}
            >${name}</button>
          `)}
        </div>
      </div>
    `;
  }

  // ── Year grid view (decade) ───────────────────────────────────────────────

  private _renderYearGrid(): TemplateResult {
    const base    = this._yearBase;
    const years   = Array.from({ length: 12 }, (_, i) => base + i);
    const selYear = this._firstSelectedDate()?.getFullYear() ?? -1;
    const curYear = new Date().getFullYear();

    return html`
      <div class="dp-view-panel">
        <div part="header" class="dp-header">
          <button part="nav-btn" class="dp-nav-btn" type="button" aria-label="Previous decade"
            @click=${this._prevDecade.bind(this)}>‹</button>
          <span class="dp-decade-label">${base} – ${base + 11}</span>
          <button part="nav-btn" class="dp-nav-btn" type="button" aria-label="Next decade"
            @click=${this._nextDecade.bind(this)}>›</button>
        </div>

        <div class="dp-year-grid">
          ${years.map(y => html`
            <button
              type="button"
              part=${['year-cell', y === selYear && 'year-cell--selected'].filter(Boolean).join(' ')}
              class=${classMap({
                'dp-year-cell':          true,
                'dp-year-cell--selected': y === selYear,
                'dp-year-cell--today':    y === curYear,
              })}
              @click=${() => this._selectYear(y)}
            >${y}</button>
          `)}
        </div>
      </div>
    `;
  }

  // ── Time picker ───────────────────────────────────────────────────────────

  private _renderTimePicker(): TemplateResult {
    return html`
      <div part="time-section" class="dp-time-section">
        ${this._renderSpinner('h', this._timeH, this.hourFormat === '12' ? 12 : 23)}
        <span class="dp-time-sep" aria-hidden="true">:</span>
        ${this._renderSpinner('m', this._timeM, 59)}
        ${this.showSeconds ? html`
          <span class="dp-time-sep" aria-hidden="true">:</span>
          ${this._renderSpinner('s', this._timeS, 59)}
        ` : nothing}
        ${this.hourFormat === '12' ? html`
          <button
            type="button"
            class="dp-ampm-btn"
            aria-label="Toggle AM/PM"
            @click=${this._toggleAmPm.bind(this)}
          >${this._ampm}</button>
        ` : nothing}
      </div>
    `;
  }

  private _renderSpinner(field: 'h' | 'm' | 's', val: number, max: number): TemplateResult {
    const label = field === 'h' ? 'Hours' : field === 'm' ? 'Minutes' : 'Seconds';
    return html`
      <div class="dp-spinner" role="group" aria-label=${label}>
        <button type="button" class="dp-spin-btn" aria-label="Increment ${label}"
          @click=${() => this._stepTime(field, 1)}>▲</button>
        <input
          type="text"
          class="dp-spin-input"
          inputmode="numeric"
          .value=${live(String(val).padStart(2, '0'))}
          aria-label=${label}
          @change=${(e: Event) => this._setTimeField(field, (e.target as HTMLInputElement).value)}
        />
        <button type="button" class="dp-spin-btn" aria-label="Decrement ${label}"
          @click=${() => this._stepTime(field, -1)}>▼</button>
      </div>
    `;
  }

  // ── Button bar ────────────────────────────────────────────────────────────

  private _renderButtonBar(): TemplateResult {
    return html`
      <div part="button-bar" class="dp-button-bar">
        <button type="button" class="dp-bar-btn dp-bar-btn--today"
          @click=${this._goToday.bind(this)}>Today</button>
        <button type="button" class="dp-bar-btn dp-bar-btn--clear"
          @click=${this._clear.bind(this)}>Clear</button>
      </div>
    `;
  }

  // ═══════════════════════════════════════════════════════════════════════════
  // STYLES
  // ═══════════════════════════════════════════════════════════════════════════

  static override styles = [styles];
}

