// Initialize critical icons in local registry
Object.entries(CRITICAL_ICONS).forEach(([name, svg]) => {
  localRegistry.set(name, svg);
});

// Default library: Bootstrap Icons
registry.set('default', (name: string) => 
  `https://cdn.jsdelivr.net/npm/bootstrap-icons@1.11.0/icons/${name}.svg`
);

export function registerLibrary(name: string, resolver: IconResolver) {
  registry.set(name, resolver);
}

export function getResolver(name: string): IconResolver | undefined {
  return registry.get(name);
}

export function registerLocalIcon(name: string, svgContent: string) {
  localRegistry.set(name, svgContent);
}

export function getLocalIcon(name: string): string | undefined {
  return localRegistry.get(name);
}

export function hasLocalIcon(name: string): boolean {
  return localRegistry.has(name);
}