import { LitElement, html, nothing, type CSSResultGroup } from 'lit';
import { property, state } from 'lit/decorators.js';
import { classMap } from 'lit/directives/class-map.js';
import { ifDefined } from 'lit/directives/if-defined.js';
import styles from './styles.js';

export type InputTextVariant = 'outlined' | 'filled';
export type InputTextSize    = 'small' | 'medium' | 'large';
export type InputTextType    = 'text' | 'password' | 'email' | 'number' | 'tel' | 'url' | 'search';

/**
 * uwc-inputtext
 *
 * Text input component with PrimeNG-level parity.
 *
 * @attr value          - Current input value.
 * @attr placeholder    - Placeholder text.
 * @attr type           - Native input type. Default: text.
 * @attr variant        - outlined | filled. Default: outlined.
 * @attr size           - small | medium | large. Default: medium.
 * @attr disabled       - Disable the input.
 * @attr readonly       - Make the input read-only.
 * @attr invalid        - Mark the input as invalid (red border).
 * @attr fluid          - Stretch to fill container width.
 * @attr maxlength      - Maximum character count.
 * @attr name           - Input name for form submission.
 * @attr autocomplete   - Native autocomplete attribute.
 *
 * @slot prefix - Icon/content shown before the input.
 * @slot suffix - Icon/content shown after the input.
 *
 * @fires uwc-input  - Fired on every keystroke.
 * @fires uwc-change - Fired when value is committed.
 * @fires uwc-focus  - Fired on focus.
 * @fires uwc-blur   - Fired on blur.
 *
 * @csspart wrapper - The outer wrapper div.
 * @csspart input   - The native <input> element.
 *
 * @cssprop --uwc-input-bg                - Background color.
 * @cssprop --uwc-input-border            - Border shorthand.
 * @cssprop --uwc-input-radius            - Border radius.
 * @cssprop --uwc-input-color             - Text color.
 * @cssprop --uwc-input-placeholder-color - Placeholder color.
 * @cssprop --uwc-input-font-size         - Font size.
 * @cssprop --uwc-input-padding-x         - Horizontal padding.
 * @cssprop --uwc-input-padding-y         - Vertical padding.
 */
export class UwcInputText extends LitElement {

  static override styles: CSSResultGroup = [styles];

  // ── Core ─────────────────────────────────────────────────────────

  @property() value        = '';
  @property() placeholder?: string;
  @property() type: InputTextType = 'text';
  @property() name?: string;
  @property() autocomplete?: string;
  @property({ type: Number }) maxlength?: number;

  // ── Appearance ────────────────────────────────────────────────────

  @property({ reflect: true }) variant: InputTextVariant = 'outlined';
  @property({ reflect: true }) size:    InputTextSize    = 'medium';

  // ── State modifiers ───────────────────────────────────────────────

  @property({ type: Boolean, reflect: true }) disabled = false;
  @property({ type: Boolean, reflect: true }) readonly = false;
  @property({ type: Boolean, reflect: true }) invalid  = false;
  @property({ type: Boolean, reflect: true }) fluid    = false;

  // ── Slot detection ────────────────────────────────────────────────

  @state() private _hasPrefix = false;
  @state() private _hasSuffix = false;

  // ── Lifecycle ─────────────────────────────────────────────────────

  override firstUpdated() {
    this._detectSlots();
  }

  private _detectSlots() {
    this._hasPrefix = this.querySelector('[slot="prefix"]') !== null;
    this._hasSuffix = this.querySelector('[slot="suffix"]') !== null;
    if (this._hasPrefix) this.setAttribute('has-prefix', '');
    else this.removeAttribute('has-prefix');
    if (this._hasSuffix) this.setAttribute('has-suffix', '');
    else this.removeAttribute('has-suffix');
  }

  // ── Handlers ─────────────────────────────────────────────────────

  private _onInput(e: Event) {
    const input = e.target as HTMLInputElement;
    this.value = input.value;
    this.dispatchEvent(new CustomEvent('uwc-input', {
      bubbles: true, composed: true,
      detail: { value: this.value, originalEvent: e },
    }));
  }

  private _onChange(e: Event) {
    const input = e.target as HTMLInputElement;
    this.value = input.value;
    this.dispatchEvent(new CustomEvent('uwc-change', {
      bubbles: true, composed: true,
      detail: { value: this.value, originalEvent: e },
    }));
  }

  // ── Render ────────────────────────────────────────────────────────

  override render() {
    const classes = classMap({
      'uwc-input': true,
      [`uwc-input--${this.variant}`]: true,
      [`uwc-input--${this.size}`]:    this.size !== 'medium',
      'uwc-input--invalid':  this.invalid,
      'uwc-input--disabled': this.disabled,
    });

    return html`
      <div part="wrapper" class=${classes}>
        ${this._hasPrefix
          ? html`<span class="uwc-input__prefix"><slot name="prefix"></slot></span>`
          : nothing}
        <input
          part="input"
          type=${this.type}
          .value=${this.value}
          placeholder=${ifDefined(this.placeholder)}
          name=${ifDefined(this.name)}
          autocomplete=${ifDefined(this.autocomplete)}
          maxlength=${ifDefined(this.maxlength)}
          ?disabled=${this.disabled}
          ?readonly=${this.readonly}
          @input=${this._onInput}
          @change=${this._onChange}
          @focus=${() => this.dispatchEvent(new CustomEvent('uwc-focus', { bubbles: true, composed: true }))}
          @blur=${()  => this.dispatchEvent(new CustomEvent('uwc-blur',  { bubbles: true, composed: true }))}
        />
        ${this._hasSuffix
          ? html`<span class="uwc-input__suffix"><slot name="suffix"></slot></span>`
          : nothing}
      </div>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap { 'uwc-inputtext': UwcInputText; }
}
