import { css } from 'lit';
import { hostReset, floatingPanel, placementOriginsExtended } from '../styles/mixins.js';
import * as t from '../styles/tokens.js';

export default [
  hostReset,
  floatingPanel('.dp-panel', { durationVar: '--uwc-dp-duration', durationDefault: '160ms' }),
  placementOriginsExtended,
  css`
    :host           { display: inline-block; position: relative; }
    :host([inline]) { display: block; }

    /* ── Trigger / Input ────────────────────────────────────────────────────── */
    .dp-trigger {
      display: inline-flex;
      align-items: center;
      background:    var(--uwc-dp-trigger-bg,     ${t.surface});
      border:        var(--uwc-dp-trigger-border, 1px solid #d0cfc9);
      border-radius: var(--uwc-dp-trigger-radius, ${t.radiusLg});
      min-width: 180px;
      overflow:  hidden;
      transition: border-color ${t.durationBase}, box-shadow ${t.durationBase};
    }
    .dp-trigger:focus-within,
    .dp-trigger--open {
      border-color: var(--uwc-dp-primary, var(--uwc-color-primary, ${t.primary}));
      box-shadow: 0 0 0 3px color-mix(in oklab, var(--uwc-dp-primary, var(--uwc-color-primary, ${t.primary})) 20%, transparent);
    }
    .dp-trigger--disabled { opacity: 0.5; pointer-events: none; }
    .dp-trigger--readonly { background: ${t.surfaceRaised}; }

    .dp-input {
      flex: 1;
      min-width: 0;
      padding: ${t.space2} 10px;
      border: none;
      outline: none;
      font-family:    var(--uwc-font-family, inherit);
      font-size:      var(--uwc-dp-trigger-font-size, ${t.fontSizeSm});
      color:          var(--uwc-dp-trigger-color, ${t.text});
      background:     transparent;
      cursor:         pointer;
      white-space:    nowrap;
      overflow:       hidden;
      text-overflow:  ellipsis;
    }
    .dp-input::placeholder { color: ${t.textMuted}; }

    .dp-clear-btn,
    .dp-cal-icon {
      flex-shrink: 0;
      display: flex;
      align-items: center;
      justify-content: center;
      border: none;
      background: transparent;
      cursor: pointer;
      padding: 0 ${t.space2};
      height: 36px;
      color: ${t.textMuted};
      transition: color ${t.durationFast};
    }
    .dp-clear-btn:hover,
    .dp-cal-icon:hover { color: ${t.textSecondary}; }
    .dp-clear-btn  { font-size: ${t.fontSizeXs}; }
    .dp-cal-icon   { font-size: ${t.fontSizeMd}; }
    .dp-cal-icon:disabled { opacity: 0.4; cursor: not-allowed; }

    /* ── Floating panel (visual) ────────────────────────────────────────────── */
    .dp-panel {
      background:    var(--uwc-dp-bg,     ${t.surface});
      border:        var(--uwc-dp-border, 1px solid ${t.border});
      border-radius: var(--uwc-dp-radius, ${t.radiusXl});
      box-shadow:    var(--uwc-dp-shadow, ${t.shadowLg});
      z-index:       var(--uwc-dp-z,     ${t.zFloat});
      overflow:      hidden;
      user-select:   none;
    }

    /* ── Inline variant ─────────────────────────────────────────────────────── */
    .dp-panel--inline {
      position: static !important;
      inset: unset !important;
      margin: 0 !important;
      opacity: 1 !important;
      transform: none !important;
      display: inline-block;
    }

    /* ── Date view grid ─────────────────────────────────────────────────────── */
    .dp-date-view {
      display: grid;
      grid-template-columns: repeat(var(--dp-months, 1), auto);
    }
    .dp-month-panel {
      padding: ${t.space4};
      min-width: 268px;
    }
    .dp-month-panel + .dp-month-panel { border-left: 1px solid ${t.borderSubtle}; }

    /* ── Header ─────────────────────────────────────────────────────────────── */
    .dp-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      margin-bottom: ${t.space3};
    }
    .dp-header-labels { display: flex; gap: ${t.space1}; align-items: center; }

    .dp-month-label,
    .dp-year-label {
      font-size:   ${t.fontSizeMd};
      font-weight: ${t.fontWeightSemibold};
      font-family: inherit;
      background:  none;
      border:      none;
      cursor:      pointer;
      color:       var(--uwc-dp-header-color, ${t.text});
      padding:     3px 6px;
      border-radius: ${t.radiusSm};
      transition: background ${t.durationFast};
    }
    .dp-month-label:hover,
    .dp-year-label:hover { background: ${t.hoverBg}; }

    .dp-decade-label { font-size: ${t.fontSizeMd}; font-weight: ${t.fontWeightSemibold}; color: ${t.text}; padding: 3px 6px; }

    .dp-nav-btn {
      width: 28px;
      height: 28px;
      border-radius: ${t.radiusMd};
      border:     none;
      background: none;
      cursor:     pointer;
      font-size:  ${t.fontSizeLg};
      color:      ${t.textSecondary};
      line-height: 1;
      display: flex;
      align-items: center;
      justify-content: center;
      transition: background ${t.durationFast}, color ${t.durationFast};
    }
    .dp-nav-btn:hover { background: ${t.hoverBg}; color: ${t.text}; }
    .dp-nav-spacer { width: 28px; flex-shrink: 0; }

    /* ── Day-name headers ───────────────────────────────────────────────────── */
    .dp-day-headers { display: grid; grid-template-columns: repeat(7, 1fr); gap: 2px; margin-bottom: ${t.space1}; }
    .dp-day-headers--week { grid-template-columns: 24px repeat(7, 1fr); }
    .dp-day-name { text-align: center; font-size: ${t.fontSizeXs}; font-weight: ${t.fontWeightMedium}; color: ${t.textDisabled}; padding: 3px 0; }
    .dp-week-label { text-align: center; font-size: 10px; color: ${t.textDisabled}; padding: 3px 0; }

    /* ── Day grid ───────────────────────────────────────────────────────────── */
    .dp-days-grid { display: grid; grid-template-columns: repeat(7, 1fr); gap: 2px; }
    .dp-days-grid--week { grid-template-columns: 24px repeat(7, 1fr); }
    .dp-week-num { display: flex; align-items: center; justify-content: center; font-size: 10px; color: ${t.textDisabled}; }

    /* ── Day cell ───────────────────────────────────────────────────────────── */
    .dp-day {
      width: 100%;
      aspect-ratio: 1/1;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: ${t.fontSizeSm};
      border-radius: ${t.radiusFull};
      border: none;
      background: none;
      cursor: pointer;
      color: ${t.text};
      transition: background ${t.durationFast}, color ${t.durationFast};
      position: relative;
    }
    .dp-day:hover:not(:disabled):not(.dp-day--selected) {
      background: var(--uwc-dp-day-hover-bg, rgba(99,102,241,0.08));
    }
    .dp-day--other-month { color: ${t.textDisabled}; }
    .dp-day--today       { border: 1.5px solid var(--uwc-dp-day-today-border, var(--uwc-color-primary, ${t.primary})); font-weight: ${t.fontWeightSemibold}; }
    .dp-day--selected    { background: var(--uwc-dp-day-selected-bg, var(--uwc-color-primary, ${t.primary})); color: var(--uwc-dp-day-selected-color, #fff); font-weight: ${t.fontWeightSemibold}; }
    .dp-day--range-start,
    .dp-day--range-end   { background: var(--uwc-dp-day-selected-bg, var(--uwc-color-primary, ${t.primary})); color: var(--uwc-dp-day-selected-color, #fff); border-radius: ${t.radiusFull}; z-index: 1; }
    .dp-day--in-range    { background: var(--uwc-dp-range-bg, rgba(99,102,241,0.1)); border-radius: 0; }
    .dp-day--disabled    { color: ${t.textDisabled}; cursor: not-allowed; opacity: 0.5; }

    /* ── Month / Year grid ──────────────────────────────────────────────────── */
    .dp-month-grid,
    .dp-year-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: ${t.space1}; padding: ${t.space3} ${t.space4}; }

    .dp-month-cell,
    .dp-year-cell {
      display: flex;
      align-items: center;
      justify-content: center;
      padding: ${t.space2} ${t.space1};
      font-size: ${t.fontSizeSm};
      border-radius: ${t.radiusMd};
      border: none;
      background: none;
      cursor: pointer;
      color: ${t.text};
      transition: background ${t.durationFast};
    }
    .dp-month-cell:hover,
    .dp-year-cell:hover { background: ${t.hoverBg}; }
    .dp-month-cell--selected,
    .dp-year-cell--selected {
      background: var(--uwc-dp-day-selected-bg, var(--uwc-color-primary, ${t.primary}));
      color: var(--uwc-dp-day-selected-color, #fff);
      font-weight: ${t.fontWeightMedium};
    }
    .dp-month-cell--current,
    .dp-year-cell--current  { font-weight: ${t.fontWeightSemibold}; }
    .dp-month-cell--disabled,
    .dp-year-cell--disabled { opacity: 0.4; cursor: not-allowed; }

    /* ── Time picker ────────────────────────────────────────────────────────── */
    .dp-time-picker {
      display: flex;
      align-items: center;
      justify-content: center;
      gap: ${t.space2};
      padding: ${t.space3} ${t.space4};
      border-top: 1px solid ${t.borderSubtle};
    }
    .dp-time-input {
      width: 52px;
      padding: ${t.space1} ${t.space2};
      border: 1px solid ${t.border};
      border-radius: ${t.radiusMd};
      font-family: inherit;
      font-size:   ${t.fontSizeSm};
      text-align:  center;
      outline: none;
      color: ${t.text};
      transition: border-color ${t.durationBase};
    }
    .dp-time-input:focus { border-color: var(--uwc-dp-primary, var(--uwc-color-primary, ${t.primary})); }
    .dp-time-sep { font-size: ${t.fontSizeLg}; font-weight: ${t.fontWeightBold}; color: ${t.textSecondary}; }

    /* ── Button bar ─────────────────────────────────────────────────────────── */
    .dp-btn-bar {
      display: flex;
      justify-content: flex-end;
      gap: ${t.space2};
      padding: ${t.space2} ${t.space4};
      border-top: 1px solid ${t.borderSubtle};
    }
  `,
];
