import { css } from 'lit';
import { hostReset } from '../styles/mixins.js';
import * as t from '../styles/tokens.js';

export default [
  hostReset,
  css`
    :host {
      display: inline-block;
      vertical-align: middle;
    }
    :host([fluid]) { display: block; width: 100%; }

    /* ── Wrapper ────────────────────────────────────────────────────────────── */
    .uwc-input {
      --_bg:        var(--uwc-input-bg,                ${t.surface});
      --_border:    var(--uwc-input-border,            1px solid #d1d5db);
      --_radius:    var(--uwc-input-radius,            ${t.radiusMd});
      --_color:     var(--uwc-input-color,             ${t.text});
      --_ph-color:  var(--uwc-input-placeholder-color, ${t.textMuted});
      --_font-size: var(--uwc-input-font-size,         ${t.fontSizeMd});
      --_px:        var(--uwc-input-padding-x,         0.75rem);
      --_py:        var(--uwc-input-padding-y,         0.5rem);
      --_icon-gap:  0.5rem;

      display: flex;
      align-items: center;
      width: 100%;
      background:    var(--_bg);
      border:        var(--_border);
      border-radius: var(--_radius);
      overflow: hidden;
      transition: border-color ${t.durationBase}, box-shadow ${t.durationBase};
    }

    .uwc-input:focus-within {
      border-color: var(--uwc-color-primary, ${t.primary});
      box-shadow: 0 0 0 3px color-mix(in oklab, var(--uwc-color-primary, ${t.primary}) 20%, transparent);
    }

    /* ── Variants ───────────────────────────────────────────────────────────── */
    .uwc-input--filled {
      --_bg: var(--uwc-input-filled-bg, ${t.surfaceRaised});
      border-color: transparent;
    }
    .uwc-input--filled:focus-within {
      --_bg: var(--uwc-input-bg, ${t.surface});
      border-color: var(--uwc-color-primary, ${t.primary});
    }

    /* ── Invalid ────────────────────────────────────────────────────────────── */
    .uwc-input--invalid {
      border-color: var(--uwc-color-danger, ${t.danger}) !important;
    }
    .uwc-input--invalid:focus-within {
      box-shadow: 0 0 0 3px color-mix(in oklab, var(--uwc-color-danger, ${t.danger}) 20%, transparent);
    }

    /* ── Sizes ──────────────────────────────────────────────────────────────── */
    .uwc-input--small { --_font-size: ${t.fontSizeXs}; --_px: 0.5rem;  --_py: 0.3125rem; }
    .uwc-input--large { --_font-size: ${t.fontSizeLg}; --_px: 1rem;    --_py: 0.6875rem; }

    /* ── Disabled ───────────────────────────────────────────────────────────── */
    .uwc-input--disabled { pointer-events: none; opacity: 0.6; }

    /* ── Native input ───────────────────────────────────────────────────────── */
    input {
      flex: 1;
      min-width: 0;
      padding-inline: var(--_px);
      padding-block:  var(--_py);
      font-family: var(--uwc-font-family, inherit);
      font-size:   var(--_font-size);
      color:       var(--_color);
      background:  transparent;
      border:      none;
      outline:     none;
    }
    input::placeholder { color: var(--_ph-color); }
    input:disabled      { cursor: not-allowed; }

    /* ── Icon slots ─────────────────────────────────────────────────────────── */
    .uwc-input__prefix,
    .uwc-input__suffix {
      display: flex;
      align-items: center;
      flex-shrink: 0;
      color: var(--_ph-color);
    }
    .uwc-input__prefix { padding-inline-start: var(--_px); }
    .uwc-input__suffix { padding-inline-end:   var(--_px); }

    /* Shrink native input padding when slot is present */
    :host([has-prefix]) input { padding-inline-start: var(--_icon-gap); }
    :host([has-suffix]) input { padding-inline-end:   var(--_icon-gap); }
  `,
];
