import { css } from 'lit';
import { hostReset, floatingPanel, placementOrigins } from '../styles/mixins.js';
import * as t from '../styles/tokens.js';

export default [
  hostReset,
  floatingPanel('.panel', { durationVar: '--uwc-dd-duration', durationDefault: '140ms' }),
  placementOrigins,
  css`
    :host { display: inline-block; }

    /* ── Trigger ────────────────────────────────────────────────────────────── */
    .trigger {
      display: inline-flex;
      align-items: center;
      gap: 6px;
      width: 100%;
      padding: ${t.space2} ${t.space3};
      font-family:   var(--uwc-font-family, inherit);
      font-size:     var(--uwc-dd-trigger-font-size, ${t.fontSizeSm});
      background:    var(--uwc-dd-trigger-bg,     ${t.surface});
      border:        var(--uwc-dd-trigger-border, 1px solid #d0cfc9);
      border-radius: var(--uwc-dd-trigger-radius, ${t.radiusLg});
      color:         var(--uwc-dd-trigger-color,  ${t.text});
      cursor:        pointer;
      text-align:    left;
      user-select:   none;
      min-width:     140px;
      transition:    border-color ${t.durationBase}, box-shadow ${t.durationBase};
    }
    .trigger:hover:not(:disabled) {
      border-color: color-mix(in oklab, var(--uwc-dd-trigger-border, #d0cfc9) 80%, #000);
    }
    .trigger:focus-visible {
      outline: none;
      border-color: var(--uwc-dd-trigger-focus-border, var(--uwc-color-primary, ${t.primary}));
      box-shadow: 0 0 0 3px color-mix(in oklab, var(--uwc-dd-trigger-focus-border, var(--uwc-color-primary, ${t.primary})) 20%, transparent);
    }
    .trigger:disabled {
      background: var(--uwc-dd-trigger-disabled-bg, #f5f5f0);
      color:      var(--uwc-text-disabled, ${t.textDisabled});
      cursor:     not-allowed;
    }
    .trigger--open {
      border-color: var(--uwc-dd-trigger-focus-border, var(--uwc-color-primary, ${t.primary}));
      box-shadow: 0 0 0 3px color-mix(in oklab, var(--uwc-dd-trigger-focus-border, var(--uwc-color-primary, ${t.primary})) 20%, transparent);
    }

    .trigger-label {
      flex: 1;
      overflow: hidden;
      text-overflow: ellipsis;
      white-space: nowrap;
    }
    .trigger-label.is-placeholder { color: var(--uwc-dd-trigger-placeholder, ${t.textMuted}); }

    .trigger-actions { display: flex; align-items: center; gap: ${t.space1}; flex-shrink: 0; }

    /* ── Caret ──────────────────────────────────────────────────────────────── */
    .caret { color: ${t.textMuted}; transition: transform 160ms ease; }
    .caret--open { transform: rotate(180deg); }

    /* ── Clear button ───────────────────────────────────────────────────────── */
    .clear-btn {
      font-size: ${t.fontSizeXs};
      color: ${t.textMuted};
      cursor: pointer;
      width: 18px;
      height: 18px;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: ${t.radiusFull};
      transition: background ${t.durationFast}, color ${t.durationFast};
    }
    .clear-btn:hover { background: ${t.hoverBg}; color: ${t.text}; }

    /* ── Loading spinner ────────────────────────────────────────────────────── */
    .loading-icon {
      display: block;
      width: 14px;
      height: 14px;
      border: 2px solid #ddd;
      border-top-color: var(--uwc-color-primary, ${t.primary});
      border-radius: ${t.radiusFull};
      animation: dd-spin 600ms linear infinite;
    }
    @keyframes dd-spin { to { transform: rotate(360deg); } }

    /* ── Chips (multi-select) ───────────────────────────────────────────────── */
    .chips-wrapper { display: flex; flex-wrap: wrap; gap: ${t.space1}; flex: 1; min-width: 0; }
    .chip {
      display: inline-flex;
      align-items: center;
      gap: ${t.space1};
      padding: 2px 6px 2px 8px;
      background:    var(--uwc-dd-chip-bg,    #ebe8e1);
      color:         var(--uwc-dd-chip-color, #444);
      border-radius: var(--uwc-radius-sm, ${t.radiusSm});
      font-size:     ${t.fontSizeXs};
    }
    .chip--overflow { background: ${t.borderSubtle}; color: ${t.textSecondary}; padding: 2px 8px; }

    .chip-remove {
      font-size: ${t.fontSizeSm};
      line-height: 1;
      background: none;
      border: none;
      cursor: pointer;
      color: ${t.textMuted};
      padding: 0 2px;
      transition: color ${t.durationFast};
    }
    .chip-remove:hover { color: ${t.text}; }

    /* ── Floating panel (visual) ────────────────────────────────────────────── */
    .panel {
      background:    var(--uwc-dd-panel-bg,     ${t.surface});
      border:        var(--uwc-dd-panel-border, 1px solid ${t.border});
      border-radius: var(--uwc-dd-panel-radius, ${t.radiusLg});
      box-shadow:    var(--uwc-dd-panel-shadow, ${t.shadowLg});
      z-index:       var(--uwc-dd-z,            ${t.zFloat});
      min-width:     160px;
      overflow:      hidden;
    }

    /* ── Filter input ───────────────────────────────────────────────────────── */
    .filter-wrapper {
      display: flex;
      align-items: center;
      gap: ${t.space2};
      padding: ${t.space2} ${t.space3};
      border-bottom: 1px solid ${t.borderSubtle};
    }
    .filter-icon  { color: ${t.textDisabled}; flex-shrink: 0; }
    .filter-input {
      flex: 1;
      border: none;
      outline: none;
      font-family: var(--uwc-font-family, inherit);
      font-size:   ${t.fontSizeXs};
      color:       ${t.text};
      background:  transparent;
    }
    .filter-input::placeholder { color: ${t.textDisabled}; }

    /* ── Options list ───────────────────────────────────────────────────────── */
    .options-wrapper { overflow-y: auto; max-height: var(--uwc-dd-max-height, 220px); }
    .options-list    { list-style: none; margin: 0; padding: ${t.space1} 0; }

    /* ── Group header ───────────────────────────────────────────────────────── */
    .group-header {
      display: flex;
      align-items: center;
      gap: 7px;
      padding: ${t.space2} 13px 4px;
      font-size:      ${t.fontSizeXs};
      font-weight:    ${t.fontWeightBold};
      letter-spacing: 0.08em;
      text-transform: uppercase;
      color:          var(--uwc-dd-group-color, ${t.textMuted});
      cursor:         default;
    }

    /* ── Option ─────────────────────────────────────────────────────────────── */
    .option {
      display: flex;
      align-items: center;
      gap: 9px;
      padding: ${t.space2} 13px;
      font-size:  ${t.fontSizeSm};
      color:      ${t.text};
      cursor:     pointer;
      list-style: none;
      transition: background ${t.durationFast};
    }
    .option:hover,
    .option--highlighted { background: var(--uwc-dd-option-hover-bg, ${t.hoverBg}); }
    .option--selected {
      background:  var(--uwc-dd-option-selected-bg,    rgba(99,102,241,0.08));
      color:       var(--uwc-dd-option-selected-color, var(--uwc-color-primary, ${t.primary}));
      font-weight: ${t.fontWeightMedium};
    }
    .option--selected.option--highlighted {
      background: color-mix(in oklab, var(--uwc-color-primary, ${t.primary}) 15%, transparent);
    }
    .option--disabled { color: var(--uwc-dd-option-disabled-color, ${t.textDisabled}); cursor: not-allowed; }
    .option--disabled:hover { background: transparent; }

    .opt-icon  { width: 18px; text-align: center; flex-shrink: 0; }
    .opt-label { flex: 1; }
    .opt-badge {
      font-size: ${t.fontSizeXs};
      padding: 1px 6px;
      border-radius: ${t.radiusFull};
      background: ${t.borderSubtle};
      color: ${t.textSecondary};
    }
    .opt-check { color: var(--uwc-color-primary, ${t.primary}); margin-left: auto; }

    /* ── Empty state ────────────────────────────────────────────────────────── */
    .empty { padding: 20px ${t.space4}; text-align: center; font-size: ${t.fontSizeXs}; color: ${t.textDisabled}; }
  `,
];
