import { LitElement, html, nothing, type TemplateResult, type PropertyValues } from 'lit';
import styles from './styles.js';
import { property, query, state } from 'lit/decorators.js';
import { repeat } from 'lit/directives/repeat.js';
import { classMap } from 'lit/directives/class-map.js';
import { styleMap } from 'lit/directives/style-map.js';
import type { Placement, MenuItem, MenuItemCommandEvent, MenuItemSelectEventDetail } from '../types.js';
import { emit, escapeHtml } from '../utils/dom.utils.js';
import { PlacementController } from '../utils/placement.controller.js';

/**
 * uwc-menu
 *
 * Click-triggered popup menu driven by the MenuItem model.
 * Supports separators, icons, badges, disabled states, submenus (hover/arrow),
 * full keyboard navigation (Arrow↑↓, Home, End, Enter, Escape, ArrowRight/Left
 * for submenus) and ARIA menuitem roles.
 *
 * @attr items          - MenuItem[] — the menu item model.
 * @attr trigger-id     - External trigger id.
 * @attr placement      - Default: bottom-start.
 * @attr offset         - Gap px. Default: 6.
 *
 * @fires uwc-show
 * @fires uwc-hide
 * @fires uwc-item-select  — detail: { item, originalEvent }
 *
 * @slot trigger        - Element that opens the menu on click.
 *
 * @csspart panel
 * @csspart item
 * @csspart item-icon
 * @csspart item-label
 * @csspart item-badge
 * @csspart separator
 * @csspart submenu-panel
 *
 * @cssprop --uwc-menu-bg
 * @cssprop --uwc-menu-border
 * @cssprop --uwc-menu-radius
 * @cssprop --uwc-menu-shadow
 * @cssprop --uwc-menu-item-hover-bg
 * @cssprop --uwc-menu-item-hover-color
 * @cssprop --uwc-menu-item-disabled-color
 * @cssprop --uwc-menu-item-font-size
 * @cssprop --uwc-menu-item-danger-color
 * @cssprop --uwc-menu-z
 * @cssprop --uwc-menu-duration
 */
export class UwcMenu extends LitElement {

  @property({ type: String,  attribute: 'trigger-id' }) triggerId?: string;
  @property({ type: Array                             }) items: MenuItem[] = [];
  @property({ type: String                            }) placement: Placement = 'bottom-start';
  @property({ type: Number                            }) offset = 6;

  @query('#panel') private _panel!: HTMLElement;

  // Tracks which item's submenu is currently open
  @state() private _openSubmenuIndex: number | null = null;
  @state() private _focusedIndex = -1;

  private readonly _onMenuKeydown = this._handleMenuKeydown.bind(this);

  private _pc = new PlacementController(this, {
    getPanelEl: () => this._panel,

    onTriggerFound: (el) => {
      const onClick  = (e: Event): void => { e.stopPropagation(); this._pc.toggle(); };
      const onKeydown = (e: KeyboardEvent): void => {
        if ((e.key === 'ArrowDown' || e.key === 'Enter' || e.key === ' ') && !this._pc.open) {
          e.preventDefault();
          this._pc.show();
        }
      };
      el.setAttribute('aria-haspopup', 'menu');
      el.addEventListener('click',   onClick);
      el.addEventListener('keydown', onKeydown as EventListener);
      return () => {
        el.removeEventListener('click',   onClick);
        el.removeEventListener('keydown', onKeydown as EventListener);
        el.removeAttribute('aria-haspopup');
      };
    },

    dismissOnOutsideClick: true,
    dismissOnEscape:       true,

    afterShow: () => {
      this._focusedIndex    = -1;
      this._openSubmenuIndex = null;
      document.addEventListener('keydown', this._onMenuKeydown);
      emit(this, 'uwc-show');
      // Focus first focusable item after paint
      requestAnimationFrame(() => this._focusItem(this._firstFocusableIndex()));
    },

    afterHide: () => {
      document.removeEventListener('keydown', this._onMenuKeydown);
      this._openSubmenuIndex = null;
      this._focusedIndex     = -1;
      emit(this, 'uwc-hide');
    },
  });

  // ── Lifecycle ────────────────────────────────────────────────────

  override firstUpdated(): void {
    this._pc.firstUpdated(
      this.triggerId ?? null,
      this.shadowRoot!.querySelector<HTMLSlotElement>('slot[name="trigger"]'),
    );
  }

  protected override updated(changed: PropertyValues): void {
    super.updated(changed);
    this._pc.updated(
      changed as Map<PropertyKey, unknown>,
      this.triggerId ?? null,
      this.shadowRoot!.querySelector<HTMLSlotElement>('slot[name="trigger"]'),
    );
  }

  // ── Item helpers ─────────────────────────────────────────────────

  /** Flat array of visible, non-separator items — used for keyboard nav. */
  private _focusableItems(): MenuItem[] {
    return this.items.filter(it => !it.separator && it.visible !== false && !it.disabled);
  }

  private _firstFocusableIndex(): number {
    return this.items.findIndex(it => !it.separator && it.visible !== false && !it.disabled);
  }

  private _focusItem(idx: number): void {
    if (idx < 0) return;
    this._focusedIndex = idx;
    const btn = this._panel?.querySelector<HTMLElement>(`[data-menu-index="${idx}"]`);
    btn?.focus();
  }

  private _itemToFlatIndex(item: MenuItem): number {
    return this.items.indexOf(item);
  }

  // ── Keyboard navigation ──────────────────────────────────────────

  private _handleMenuKeydown(e: KeyboardEvent): void {
    const items       = this.items;
    const focusable   = items
      .map((it, i) => ({ it, i }))
      .filter(({ it }) => !it.separator && it.visible !== false && !it.disabled);
    const curPos      = focusable.findIndex(({ i }) => i === this._focusedIndex);

    switch (e.key) {
      case 'ArrowDown': {
        e.preventDefault();
        const next = focusable[(curPos + 1) % focusable.length];
        if (next) this._focusItem(next.i);
        break;
      }
      case 'ArrowUp': {
        e.preventDefault();
        const prev = focusable[(curPos - 1 + focusable.length) % focusable.length];
        if (prev) this._focusItem(prev.i);
        break;
      }
      case 'Home':
        e.preventDefault();
        if (focusable[0]) this._focusItem(focusable[0].i);
        break;
      case 'End':
        e.preventDefault();
        if (focusable.at(-1)) this._focusItem(focusable.at(-1)!.i);
        break;
      case 'ArrowRight': {
        const focused = items[this._focusedIndex];
        if (focused?.items?.length) {
          this._openSubmenuIndex = this._focusedIndex;
          // Focus first item of submenu
          requestAnimationFrame(() => {
            const subItem = this._panel?.querySelector<HTMLElement>(
              `[data-submenu-index="${this._focusedIndex}"] [data-sub-item-index="0"]`
            );
            subItem?.focus();
          });
        }
        break;
      }
      case 'ArrowLeft':
        this._openSubmenuIndex = null;
        break;
      case 'Tab':
        // Natural tab flow — close menu
        this._pc.hide();
        break;
      // Escape handled by PlacementController
    }
  }

  // ── Item command execution ────────────────────────────────────────

  private _executeItem(item: MenuItem, e: Event): void {
    if (item.disabled) return;
    const ev: MenuItemCommandEvent = { originalEvent: e, item };
    item.command?.(ev);
    emit<MenuItemSelectEventDetail>(this, 'uwc-item-select', { item, originalEvent: e });
    if (!item.items?.length) this._pc.hide();
  }

  private _handleItemClick(item: MenuItem, idx: number, e: Event): void {
    e.stopPropagation();
    if (item.separator || item.disabled) return;
    if (item.items?.length) {
      this._openSubmenuIndex = this._openSubmenuIndex === idx ? null : idx;
      return;
    }
    this._executeItem(item, e);
  }

  private _handleItemMouseEnter(idx: number, item: MenuItem): void {
    if (item.items?.length) {
      this._openSubmenuIndex = idx;
    } else if (this._openSubmenuIndex !== null) {
      this._openSubmenuIndex = null;
    }
  }

  // ── Render helpers ────────────────────────────────────────────────

  private _renderItem(item: MenuItem, idx: number): TemplateResult {
    if (item.visible === false) return html``;

    if (item.separator) {
      return html`<li part="separator" class="separator" role="separator" aria-hidden="true"></li>`;
    }

    const hasSubmenu  = Boolean(item.items?.length);
    const isSubmenuOpen = this._openSubmenuIndex === idx;
    const isFocused   = this._focusedIndex === idx;

    const labelContent = item.escape === true
      ? html`${item.label ?? ''}`
      // eslint-disable-next-line lit/no-invalid-html
      : html`<span .innerHTML=${escapeHtml(item.label ?? '')}></span>`;

    return html`
      <li
        part="item"
        class=${classMap({
          'item':           true,
          'item--disabled': !!item.disabled,
          'item--active':   isSubmenuOpen,
          'item--focused':  isFocused,
          'item--danger':   !!item.danger,
        })}
        style=${item.style ? styleMap(item.style as Record<string, string>) : ''}
        data-menu-index=${idx}
        role="none"
        @mouseenter=${() => this._handleItemMouseEnter(idx, item)}
      >
        ${item.url && !item.disabled
          ? html`
            <a
              href=${item.url}
              target=${item.target ?? '_self'}
              title=${item.title ?? ''}
              role="menuitem"
              data-menu-index=${idx}
              class="item-inner"
              tabindex=${isFocused ? '0' : '-1'}
              @click=${(e: Event) => this._executeItem(item, e)}
            >
              ${this._renderItemInner(item, hasSubmenu)}
            </a>`
          : html`
            <button
              type="button"
              role="menuitem"
              data-menu-index=${idx}
              class="item-inner"
              tabindex=${isFocused ? '0' : '-1'}
              ?disabled=${item.disabled}
              title=${item.title ?? ''}
              aria-haspopup=${hasSubmenu ? 'menu' : 'false'}
              aria-expanded=${hasSubmenu ? String(isSubmenuOpen) : 'false'}
              @click=${(e: Event) => this._handleItemClick(item, idx, e)}
              @focus=${() => { this._focusedIndex = idx; }}
            >
              ${this._renderItemInner(item, hasSubmenu)}
            </button>`
        }

        ${hasSubmenu && isSubmenuOpen ? html`
          <ul
            class="submenu-panel"
            part="submenu-panel"
            role="menu"
            data-submenu-index=${idx}
          >
            ${repeat(
              (item.items ?? []).filter(sub => sub.visible !== false),
              (sub) => sub.id ?? sub.label,
              (sub, subIdx) => this._renderSubItem(sub, subIdx, idx),
            )}
          </ul>` : nothing}
      </li>`;
  }

  private _renderItemInner(item: MenuItem, hasSubmenu: boolean): TemplateResult {
    return html`
      ${item.icon
        ? html`<span part="item-icon" class="item-icon ${item.iconClass ?? ''}"><uwc-icon name=${item.icon} size="15px"></uwc-icon></span>`
        : nothing}
      <span part="item-label" class="item-label">${item.label ?? ''}</span>
      ${item.badge
        ? html`<span part="item-badge" class="item-badge ${item.badgeClass ?? ''}">${item.badge}</span>`
        : nothing}
      ${hasSubmenu
        ? html`<span class="item-chevron" aria-hidden="true">›</span>`
        : nothing}`;
  }

  private _renderSubItem(item: MenuItem, subIdx: number, parentIdx: number): TemplateResult {
    if (item.separator) {
      return html`<li class="separator" role="separator" aria-hidden="true"></li>`;
    }
    return html`
      <li role="none" class=${classMap({ 'item': true, 'item--disabled': !!item.disabled })}>
        <button
          type="button"
          role="menuitem"
          data-sub-item-index=${subIdx}
          class="item-inner"
          tabindex="-1"
          ?disabled=${item.disabled}
          title=${item.title ?? ''}
          @click=${(e: Event) => {
            e.stopPropagation();
            if (!item.disabled) this._executeItem(item, e);
          }}
        >
          ${this._renderItemInner(item, false)}
        </button>
      </li>`;
  }

  // ── Public API ───────────────────────────────────────────────────

  show():   void { this._pc.show(); }
  hide():   void { this._pc.hide(); }
  toggle(): void { this._pc.toggle(); }
  get isOpen(): boolean { return this._pc.open; }

  // ── Render ───────────────────────────────────────────────────────

  protected override render() {
    const isExternal = Boolean(this.triggerId);
    const open       = this._pc.open;
    const visible    = this.items.filter(it => it.visible !== false);

    return html`
      ${!isExternal
        ? html`<slot name="trigger" part="trigger"></slot>`
        : nothing}

      <div
        id="panel"
        part="panel"
        popover="manual"
        role="menu"
        class="panel ${open ? 'is-open' : ''}"
        data-placement=${this.placement}
        aria-orientation="vertical"
      >
        <ul class="list" role="presentation">
          ${repeat(
            visible,
            (item) => item.id ?? item.label ?? Math.random(),
            (item, idx) => this._renderItem(item, idx),
          )}
        </ul>
      </div>`;
  }

  static override styles = [styles];
}

declare global {
  interface HTMLElementTagNameMap { 'uwc-menu': UwcMenu; }
}
