import { LitElement, html, css, type PropertyValues } from 'lit';
import { property, state } from 'lit/decorators.js';
import { unsafeSVG } from 'lit/directives/unsafe-svg.js';
import { styleMap } from 'lit/directives/style-map.js';
import { getResolver, getLocalIcon, hasLocalIcon } from './library.js';

export class UwcIcon extends LitElement {
  static override styles = css`
    :host {
      display: inline-flex;
      vertical-align: middle;
      justify-content: center;
      align-items: center;
    }

    /* This ensures the injected SVG obeys the host's size and color */
    .icon-container, 
    .icon-container svg {
      display: block;
      width: var(--icon-size);
      height: var(--icon-size);
      fill: var(--icon-color);
    }

    /* Spin animation for loading icons */
    @keyframes spin {
      from {
        transform: rotate(0deg);
      }
      to {
        transform: rotate(360deg);
      }
    }

    .icon-container.spin svg {
      animation: spin 1s linear infinite;
    }
  `;

  @property({ reflect: true }) name = '';
  @property({ reflect: true }) library = 'default';
  @property({ reflect: true }) size = '18px';
  @property({ reflect: true }) color = 'currentColor';
  @property({ type: Boolean, reflect: true }) spin = false;
  @property() src?: string;

  @state() private svgContent = '';
  @state() private isLocalIcon = false;

  protected override updated(changedProperties: PropertyValues) {
    if (changedProperties.has('name') || changedProperties.has('library') || changedProperties.has('src')) {
      this.loadIcon();
    }
  }

  private async loadIcon() {
    // Priority 1: Check if custom src is provided
    if (this.src) {
      await this.fetchRemoteIcon(this.src);
      return;
    }

    // Priority 2: Check local registry for critical icons
    if (hasLocalIcon(this.name)) {
      this.loadLocalIcon();
      return;
    }

    // Priority 3: Fallback to remote fetch
    const url = this.resolveUrl();
    if (url) {
      await this.fetchRemoteIcon(url);
    } else {
      this.svgContent = '';
    }
  }

  private loadLocalIcon() {
    const localSvg = getLocalIcon(this.name);
    if (localSvg) {
      this.isLocalIcon = true;
      this.svgContent = this.cleanSvg(localSvg);
      this.dispatchEvent(new CustomEvent('uwc-load', { 
        detail: { source: 'local-registry' } 
      }));
    }
  }

  private async fetchRemoteIcon(url: string) {
    try {
      const response = await fetch(url, { mode: 'cors' });
      if (response.ok) {
        const rawSvg = await response.text();
        this.isLocalIcon = false;
        this.svgContent = this.cleanSvg(rawSvg);
        this.dispatchEvent(new CustomEvent('uwc-load', { 
          detail: { source: 'remote' } 
        }));
      } else {
        throw new Error(`Failed to fetch icon: ${response.status}`);
      }
    } catch (err) {
      this.svgContent = '';
      this.dispatchEvent(new CustomEvent('uwc-error', { 
        detail: { err, iconName: this.name } 
      }));
    }
  }

  private cleanSvg(rawSvg: string): string {
    // If the fetched SVG has hardcoded width/height, they can override our CSS.
    // We strip them out to let our container control the dimensions.
    return rawSvg.replace(/<svg([^>]*)>/, (match, attrs) => {
      const cleanedAttrs = attrs
        .replace(/\b(width|height|fill)\b="[^"]*"/g, '')
        .trim();
      return `<svg ${cleanedAttrs}>`;
    });
  }

  private resolveUrl(): string {
    const resolver = getResolver(this.library);
    return resolver ? resolver(this.name) : '';
  }

  override render() {
    // These styles mirror your old setAttribute logic
    const containerStyles = {
      '--icon-size': this.size,
      '--icon-color': this.color
    };

    // Auto-enable spin for loading icons or when spin property is set
    const shouldSpin = this.spin || this.name === 'loading' || this.name === 'spinner';
    const containerClass = shouldSpin ? 'icon-container spin' : 'icon-container';

    return html`
      <div 
        class="${containerClass}" 
        style=${styleMap(containerStyles)}
        role="img"
        aria-hidden="true"
        data-source="${this.isLocalIcon ? 'local' : 'remote'}"
      >
        ${unsafeSVG(this.svgContent)}
      </div>
    `;
  }
}