import { css } from 'lit';
import { hostReset } from '../styles/mixins.js';
import * as t from '../styles/tokens.js';

export default [
  hostReset,
  css`
    :host {
      display: inline-block;
      vertical-align: top;
    }
    :host([fluid]) { display: block; width: 100%; }

    /* ── Container ──────────────────────────────────────────────────────────── */
    .uwc-lb {
      --_radius:      var(--uwc-listbox-radius,     ${t.radiusMd});
      --_border:      var(--uwc-listbox-border,     1px solid #d1d5db);
      --_bg:          var(--uwc-listbox-bg,         ${t.surface});
      --_item-height: var(--uwc-listbox-item-height,2.5rem);
      --_font-size:   var(--uwc-listbox-font-size,  ${t.fontSizeMd});
      --_color:       var(--uwc-listbox-color,      var(--uwc-color-primary, ${t.primary}));

      display: flex;
      flex-direction: column;
      width: 100%;
      background:    var(--_bg);
      border:        var(--_border);
      border-radius: var(--_radius);
      overflow: hidden;
      font-size: var(--_font-size);
    }

    /* ── Filter ─────────────────────────────────────────────────────────────── */
    .uwc-lb__filter {
      display: flex;
      align-items: center;
      padding: 0.5rem;
      border-bottom: 1px solid #e5e7eb;
      gap: 0.375rem;
    }
    .uwc-lb__filter-input {
      flex: 1;
      min-width: 0;
      padding: 0.375rem 0.5rem;
      font-size: var(--_font-size);
      font-family: inherit;
      color: ${t.text};
      background: transparent;
      border: 1px solid #d1d5db;
      border-radius: ${t.radiusSm};
      outline: none;
      transition: border-color ${t.durationBase}, box-shadow ${t.durationBase};
    }
    .uwc-lb__filter-input:focus {
      border-color: var(--_color);
      box-shadow: 0 0 0 2px color-mix(in oklab, var(--_color) 20%, transparent);
    }
    .uwc-lb__filter-icon {
      color: ${t.textMuted};
      flex-shrink: 0;
    }

    /* ── Header ─────────────────────────────────────────────────────────────── */
    .uwc-lb__header {
      display: flex;
      align-items: center;
      gap: 0.5rem;
      padding: 0.5rem 0.75rem;
      border-bottom: 1px solid #e5e7eb;
      font-weight: ${t.fontWeightSemibold};
      font-size: ${t.fontSizeSm};
      color: ${t.textSecondary};
    }

    /* ── List ───────────────────────────────────────────────────────────────── */
    .uwc-lb__list {
      list-style: none;
      margin: 0;
      padding: 0.25rem 0;
      overflow-y: auto;
      max-height: var(--uwc-listbox-max-height, 14rem);
      outline: none;
    }

    /* ── Item ───────────────────────────────────────────────────────────────── */
    .uwc-lb__item {
      display: flex;
      align-items: center;
      gap: 0.5rem;
      min-height: var(--_item-height);
      padding: 0.375rem 0.75rem;
      cursor: pointer;
      transition: background-color ${t.durationFast};
      color: ${t.text};
    }
    .uwc-lb__item:hover          { background-color: ${t.hoverBg}; }
    .uwc-lb__item--selected      { background-color: ${t.selectedBg}; color: var(--_color); font-weight: ${t.fontWeightMedium}; }
    .uwc-lb__item--selected:hover{ background-color: color-mix(in oklab, ${t.selectedBg} 120%, transparent); }
    .uwc-lb__item--disabled      { pointer-events: none; opacity: 0.5; }
    .uwc-lb__item--focused       { background-color: ${t.hoverBg}; }

    /* Check icon for selected item */
    .uwc-lb__check {
      margin-inline-start: auto;
      flex-shrink: 0;
      display: none;
    }
    .uwc-lb__item--selected .uwc-lb__check { display: flex; }

    /* ── Group header ───────────────────────────────────────────────────────── */
    .uwc-lb__group-header {
      display: flex;
      align-items: center;
      padding: 0.375rem 0.75rem;
      font-size: ${t.fontSizeSm};
      font-weight: ${t.fontWeightSemibold};
      color: ${t.textSecondary};
      text-transform: uppercase;
      letter-spacing: 0.04em;
    }

    /* ── Empty ──────────────────────────────────────────────────────────────── */
    .uwc-lb__empty {
      display: flex;
      align-items: center;
      justify-content: center;
      padding: 1.5rem;
      color: ${t.textMuted};
      font-size: ${t.fontSizeSm};
    }

    /* ── Disabled host ──────────────────────────────────────────────────────── */
    :host([disabled]) .uwc-lb {
      pointer-events: none;
      opacity: 0.6;
    }

    /* ── Invalid ────────────────────────────────────────────────────────────── */
    :host([invalid]) .uwc-lb {
      border-color: var(--uwc-color-danger, ${t.danger});
    }

    /* ── Multiple select checkboxes ─────────────────────────────────────────── */
    .uwc-lb__item-cb {
      width: 1rem;
      height: 1rem;
      flex-shrink: 0;
      border: 1px solid #d1d5db;
      border-radius: ${t.radiusXs};
      display: flex;
      align-items: center;
      justify-content: center;
      transition: background-color ${t.durationBase}, border-color ${t.durationBase};
    }
    .uwc-lb__item--selected .uwc-lb__item-cb {
      background: var(--_color);
      border-color: var(--_color);
    }
  `,
];
