import { LitElement, html, nothing, type TemplateResult, type PropertyValues } from 'lit';
import styles from './styles.js';
import { property, query, state } from 'lit/decorators.js';
import { repeat } from 'lit/directives/repeat.js';
import { classMap } from 'lit/directives/class-map.js';
import { live } from 'lit/directives/live.js';
import type {
  Placement,
  SelectOption,
  DropdownChangeEventDetail,
  DropdownFilterEventDetail,
  DropdownClearEventDetail,
} from '../types.js';
import { emit } from '../utils/dom.utils.js';
import { PlacementController } from '../utils/placement.controller.js';

/**
 * uwc-dropdown
 *
 * Full-featured select / dropdown component (PrimeNG Select-level richness).
 *
 * Features:
 *  - Single and multiple selection
 *  - Client-side filter with customisable placeholder
 *  - Option groups (non-selectable headers)
 *  - Clear (×) button
 *  - Loading state with spinner
 *  - Disabled state
 *  - Full keyboard navigation (↑↓ Home End Enter Escape)
 *  - Accessible: role="combobox", aria-expanded, role="listbox",
 *    role="option", aria-selected, aria-activedescendant
 *  - Chip display for multi-select
 *
 * @attr options            - SelectOption[] — the option model.
 * @attr value              - Currently selected value (single) or value[] (multiple).
 * @attr placeholder        - Trigger placeholder text.
 * @attr multiple           - Enable multi-select (chips UI).
 * @attr filter             - Show filter input inside panel.
 * @attr filter-placeholder - Placeholder for the filter input. Default: "Search…"
 * @attr show-clear         - Show clear (×) button when a value is selected.
 * @attr loading            - Show spinner and disable interaction.
 * @attr disabled           - Disable the entire component.
 * @attr scroll-height      - Max panel height (CSS value). Default: 220px.
 * @attr auto-display-first - Select first option automatically on mount.
 * @attr empty-message      - Message shown when filter yields no results.
 * @attr placement          - Default: bottom-start.
 * @attr offset             - Gap px. Default: 4.
 * @attr max-selected-labels - Max chips shown before collapse label. Default: 3.
 *
 * @fires uwc-change  — detail: { value, label, originalEvent }
 * @fires uwc-filter  — detail: { query, originalEvent }
 * @fires uwc-clear   — detail: { previousValue }
 * @fires uwc-focus
 * @fires uwc-blur
 * @fires uwc-show
 * @fires uwc-hide
 *
 * @csspart trigger
 * @csspart label
 * @csspart chip
 * @csspart clear-btn
 * @csspart caret
 * @csspart panel
 * @csspart filter-input
 * @csspart option
 * @csspart group-header
 * @csspart empty
 * @csspart loading-icon
 *
 * @cssprop --uwc-dd-trigger-bg
 * @cssprop --uwc-dd-trigger-border
 * @cssprop --uwc-dd-trigger-radius
 * @cssprop --uwc-dd-trigger-color
 * @cssprop --uwc-dd-trigger-placeholder-color
 * @cssprop --uwc-dd-trigger-focus-border
 * @cssprop --uwc-dd-trigger-open-border
 * @cssprop --uwc-dd-trigger-disabled-bg
 * @cssprop --uwc-dd-chip-bg
 * @cssprop --uwc-dd-chip-color
 * @cssprop --uwc-dd-panel-bg
 * @cssprop --uwc-dd-panel-border
 * @cssprop --uwc-dd-panel-radius
 * @cssprop --uwc-dd-panel-shadow
 * @cssprop --uwc-dd-option-hover-bg
 * @cssprop --uwc-dd-option-selected-bg
 * @cssprop --uwc-dd-option-selected-color
 * @cssprop --uwc-dd-option-disabled-color
 * @cssprop --uwc-dd-group-color
 * @cssprop --uwc-dd-z
 * @cssprop --uwc-dd-duration
 */
export class UwcDropdown extends LitElement {

  // ── Props ────────────────────────────────────────────────────────

  @property({ type: Array                                         }) options: SelectOption[] = [];
  @property({ attribute: false                                    }) value: unknown = null;
  @property({ type: String                                        }) placement: Placement = 'bottom-start';
  @property({ type: Number                                        }) offset = 4;
  @property({ type: String                                        }) placeholder = 'Select…';
  @property({ type: Boolean, reflect: true                        }) multiple = false;
  @property({ type: Boolean                                       }) filter = false;
  @property({ type: String,  attribute: 'filter-placeholder'     }) filterPlaceholder = 'Search…';
  @property({ type: Boolean, attribute: 'show-clear'             }) showClear = false;
  @property({ type: Boolean, reflect: true                        }) loading = false;
  @property({ type: Boolean, reflect: true                        }) disabled = false;
  @property({ type: Number,  attribute: 'scroll-height'          }) override scrollHeight = 220;
  @property({ type: Boolean, attribute: 'auto-display-first'     }) autoDisplayFirst = false;
  @property({ type: String,  attribute: 'empty-message'          }) emptyMessage = 'No results found.';
  @property({ type: Number,  attribute: 'max-selected-labels'    }) maxSelectedLabels = 3;

  // ── Internal state ───────────────────────────────────────────────

  @state() private _filterQuery  = '';
  @state() private _highlightIdx = -1;
  @state() private _focusWithin  = false;

  @query('#trigger-btn')   private _triggerBtn!: HTMLButtonElement;
  @query('#filter-input')  private _filterInput?: HTMLInputElement;
  @query('#panel')         private _panel!: HTMLElement;
  @query('#options-list')  private _optionsList?: HTMLElement;

  private readonly _onDropdownKeydown = this._handleDropdownKeydown.bind(this);

  // ── Controller ───────────────────────────────────────────────────

  private _pc = new PlacementController(this, {
    getPanelEl: () => this._panel,

    // Dropdown renders its own trigger; setTriggerElement() called from firstUpdated
    onTriggerFound: (el) => {
      const onClick  = (e: Event): void => { e.stopPropagation(); this._pc.toggle(); };
      const onKeydown = (e: KeyboardEvent): void => {
        if ((e.key === 'ArrowDown' || e.key === 'Enter' || e.key === ' ') && !this._pc.open) {
          e.preventDefault(); this._pc.show();
        }
      };
      el.setAttribute('aria-haspopup', 'listbox');
      el.addEventListener('click',   onClick);
      el.addEventListener('keydown', onKeydown as EventListener);
      return () => {
        el.removeEventListener('click',   onClick);
        el.removeEventListener('keydown', onKeydown as EventListener);
        el.removeAttribute('aria-haspopup');
      };
    },

    dismissOnOutsideClick: true,
    dismissOnEscape:       true,

    afterShow: () => {
      this._filterQuery  = '';
      this._highlightIdx = this._indexOfSelectedValue();
      document.addEventListener('keydown', this._onDropdownKeydown);
      emit(this, 'uwc-show');
      // Focus filter input if present; otherwise focus option list for keyboard
      requestAnimationFrame(() => {
        if (this.filter) this._filterInput?.focus();
        this._scrollToHighlighted();
      });
    },

    afterHide: () => {
      document.removeEventListener('keydown', this._onDropdownKeydown);
      this._highlightIdx = -1;
      emit(this, 'uwc-hide');
      this._triggerBtn?.focus();
    },
  });

  // ── Lifecycle ────────────────────────────────────────────────────

  override firstUpdated(): void {
    // Dropdown uses its own rendered trigger button — bypass slot/trigger-id wiring
    this._pc.setTriggerElement(this._triggerBtn);

    if (this.autoDisplayFirst && !this._hasValue() && this.options.length) {
      const first = this.options.find(o => !o.group && !o.disabled);
      if (first) this._selectOption(first, undefined, { silent: true });
    }
  }

  protected override updated(changed: PropertyValues): void {
    super.updated(changed);
    this._pc.updated(changed as Map<PropertyKey, unknown>, null, null);
    if (changed.has('_highlightIdx')) {
      this._scrollToHighlighted();
    }
  }

  // ── Value helpers ────────────────────────────────────────────────

  private _hasValue(): boolean {
    if (this.multiple) return Array.isArray(this.value) && (this.value as unknown[]).length > 0;
    return this.value !== null && this.value !== undefined;
  }

  private _isSelected(opt: SelectOption): boolean {
    if (this.multiple) {
      return Array.isArray(this.value) && (this.value as unknown[]).includes(opt.value);
    }
    return this.value === opt.value;
  }

  private _indexOfSelectedValue(): number {
    if (!this._hasValue()) return -1;
    const visible = this._filteredOptions();
    if (this.multiple) return 0;
    return visible.findIndex(o => !o.group && o.value === this.value);
  }

  // ── Options helpers ──────────────────────────────────────────────

  private _filteredOptions(): SelectOption[] {
    if (!this._filterQuery) return this.options;
    const q = this._filterQuery.toLowerCase();
    return this.options.filter(o =>
      o.group !== undefined || o.label.toLowerCase().includes(q)
    );
  }

  private _selectableOptions(): SelectOption[] {
    return this._filteredOptions().filter(o => !o.group && !o.disabled);
  }

  private _labelForValue(val: unknown): string {
    return this.options.find(o => o.value === val)?.label ?? String(val);
  }

  private _triggerLabel(): string {
    if (!this._hasValue()) return '';
    if (this.multiple) {
      const selected = (this.value as unknown[]).map(v => this._labelForValue(v));
      if (selected.length <= this.maxSelectedLabels) return selected.join(', ');
      return `${selected.length} items selected`;
    }
    return this._labelForValue(this.value);
  }

  // ── Selection ────────────────────────────────────────────────────

  private _selectOption(
    opt: SelectOption,
    e?: Event,
    { silent = false } = {},
  ): void {
    if (opt.disabled || opt.group) return;

    let newValue: unknown;

    if (this.multiple) {
      const current = Array.isArray(this.value) ? [...(this.value as unknown[])] : [];
      const idx     = current.indexOf(opt.value);
      if (idx >= 0) current.splice(idx, 1);
      else          current.push(opt.value);
      newValue = current;
    } else {
      newValue = opt.value;
      this._pc.hide();
    }

    this.value = newValue;

    if (!silent) {
      emit<DropdownChangeEventDetail>(this, 'uwc-change', {
        value:         newValue,
        label:         opt.label,
        originalEvent: e,
      });
    }

    this.requestUpdate();
  }

  private _removeChip(val: unknown, e: Event): void {
    e.stopPropagation();
    if (!this.multiple || !Array.isArray(this.value)) return;
    const prev  = this.value as unknown[];
    this.value  = prev.filter(v => v !== val);
    emit<DropdownChangeEventDetail>(this, 'uwc-change', {
      value: this.value,
      label: this._labelForValue(val),
    });
  }

  private _clear(e: Event): void {
    e.stopPropagation();
    const prev = this.value;
    this.value = this.multiple ? [] : null;
    emit<DropdownClearEventDetail>(this, 'uwc-clear', { previousValue: prev });
    emit<DropdownChangeEventDetail>(this, 'uwc-change', {
      value: this.value,
      label: '',
    });
  }

  // ── Filter ───────────────────────────────────────────────────────

  private _handleFilterInput(e: InputEvent): void {
    this._filterQuery  = (e.target as HTMLInputElement).value;
    this._highlightIdx = 0;
    emit<DropdownFilterEventDetail>(this, 'uwc-filter', { query: this._filterQuery, originalEvent: e });
  }

  // ── Keyboard navigation ──────────────────────────────────────────

  private _handleDropdownKeydown(e: KeyboardEvent): void {
    const opts = this._selectableOptions();
    if (!opts.length) return;

    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault();
        this._highlightIdx = (this._highlightIdx + 1) % opts.length;
        break;
      case 'ArrowUp':
        e.preventDefault();
        this._highlightIdx = (this._highlightIdx - 1 + opts.length) % opts.length;
        break;
      case 'Home':
        e.preventDefault();
        this._highlightIdx = 0;
        break;
      case 'End':
        e.preventDefault();
        this._highlightIdx = opts.length - 1;
        break;
      case 'Enter':
      case ' ':
        if (e.key === ' ' && this.filter) break; // allow space in filter input
        e.preventDefault();
        if (this._highlightIdx >= 0 && opts[this._highlightIdx]) {
          this._selectOption(opts[this._highlightIdx], e);
        }
        break;
      case 'Tab':
        this._pc.hide();
        break;
      // Escape: handled by PlacementController
    }
  }

  private _scrollToHighlighted(): void {
    requestAnimationFrame(() => {
      const list = this._optionsList;
      const item = list?.querySelector<HTMLElement>('[data-highlighted="true"]');
      item?.scrollIntoView({ block: 'nearest' });
    });
  }

  // ── Render helpers ────────────────────────────────────────────────

  private _renderChips(): TemplateResult {
    if (!this.multiple || !Array.isArray(this.value)) return html``;
    const selected = (this.value as unknown[]);
    const visible  = selected.slice(0, this.maxSelectedLabels);
    const overflow = selected.length - visible.length;

    return html`
      <div class="chips-wrapper">
        ${visible.map(val => html`
          <span part="chip" class="chip">
            <span class="chip-label">${this._labelForValue(val)}</span>
            <button
              type="button"
              class="chip-remove"
              aria-label="Remove ${this._labelForValue(val)}"
              tabindex="-1"
              @click=${(e: Event) => this._removeChip(val, e)}
            >×</button>
          </span>`)}
        ${overflow > 0
          ? html`<span class="chip chip--overflow">+${overflow}</span>`
          : nothing}
      </div>`;
  }

  private _renderOptions(): TemplateResult {
    const filtered = this._filteredOptions();
    const selectable = this._selectableOptions();

    if (!filtered.length) {
      return html`<div part="empty" class="empty">${this.emptyMessage}</div>`;
    }

    return html`
      <ul
        id="options-list"
        role="listbox"
        aria-multiselectable=${this.multiple}
        class="options-list"
      >
        ${repeat(
          filtered,
          (opt) => String(opt.value ?? opt.group ?? opt.label),
          (opt) => {
            if (opt.group !== undefined) {
              return html`
                <li part="group-header" class="group-header" role="presentation">
                  ${opt.icon ? html`<span class="opt-icon">${opt.icon}</span>` : nothing}
                  <span>${opt.group || opt.label}</span>
                </li>`;
            }

            const selIdx     = selectable.indexOf(opt);
            const isHighlit  = selIdx === this._highlightIdx;
            const isSelected = this._isSelected(opt);

            return html`
              <li
                part="option"
                role="option"
                id="opt-${String(opt.value)}"
                aria-selected=${isSelected}
                aria-disabled=${opt.disabled ?? false}
                data-highlighted=${isHighlit}
                class=${classMap({
                  'option':              true,
                  'option--selected':    isSelected,
                  'option--highlighted': isHighlit,
                  'option--disabled':    !!opt.disabled,
                })}
                title=${opt.title ?? ''}
                @click=${(e: Event) => { if (!opt.disabled) this._selectOption(opt, e); }}
                @mouseenter=${() => { if (!opt.disabled) this._highlightIdx = selIdx; }}
              >
                ${opt.icon
                  ? html`<span class="opt-icon">${opt.icon}</span>`
                  : nothing}
                <span class="opt-label">${opt.label}</span>
                ${opt.badge
                  ? html`<span class="opt-badge">${opt.badge}</span>`
                  : nothing}
                ${isSelected
                  ? html`<span class="opt-check" aria-hidden="true">✓</span>`
                  : nothing}
              </li>`;
          },
        )}
      </ul>`;
  }

  // ── Render ───────────────────────────────────────────────────────

  protected override render() {
    const open     = this._pc.open;
    const hasValue = this._hasValue();
    const label    = this._triggerLabel();
    const showClearBtn = this.showClear && hasValue && !this.disabled && !this.loading;

    return html`
      <button
        id="trigger-btn"
        part="trigger"
        type="button"
        class=${classMap({
          'trigger':          true,
          'trigger--open':    open,
          'trigger--loading': this.loading,
          'trigger--empty':   !hasValue,
        })}
        ?disabled=${this.disabled || this.loading}
        aria-expanded=${open}
        aria-controls="panel"
        aria-label=${label || this.placeholder}
        @focus=${() => { this._focusWithin = true;  emit(this, 'uwc-focus'); }}
        @blur=${()  => { this._focusWithin = false; emit(this, 'uwc-blur');  }}
      >
        ${this.multiple && hasValue
          ? this._renderChips()
          : html`<span part="label" class="trigger-label ${!hasValue ? 'is-placeholder' : ''}">
                   ${hasValue ? label : this.placeholder}
                 </span>`}

        <span class="trigger-actions">
          ${showClearBtn ? html`
            <span
              part="clear-btn"
              class="clear-btn"
              role="button"
              tabindex="-1"
              aria-label="Clear"
              @click=${this._clear}
            >✕</span>` : nothing}

          ${this.loading
            ? html`<span part="loading-icon" class="loading-icon" aria-hidden="true"></span>`
            : html`<svg
                part="caret"
                class="caret ${open ? 'caret--open' : ''}"
                width="12" height="12" viewBox="0 0 12 12" fill="none"
                aria-hidden="true">
                <path d="M2 4l4 4 4-4"
                  stroke="currentColor" stroke-width="1.5"
                  stroke-linecap="round" stroke-linejoin="round"/>
              </svg>`}
        </span>
      </button>

      <div
        id="panel"
        part="panel"
        popover="manual"
        class="panel ${open ? 'is-open' : ''}"
        data-placement=${this.placement}
        style="--scroll-height: ${this.scrollHeight}"
        aria-label="Options"
      >
        ${this.filter ? html`
          <div class="filter-wrapper">
            <span class="filter-icon" aria-hidden="true">🔍</span>
            <input
              id="filter-input"
              part="filter-input"
              type="text"
              class="filter-input"
              placeholder=${this.filterPlaceholder}
              .value=${live(this._filterQuery)}
              autocomplete="off"
              @input=${this._handleFilterInput}
              @keydown=${(e: KeyboardEvent) => {
                // prevent arrow keys from scrolling the page when in filter
                if (['ArrowUp', 'ArrowDown'].includes(e.key)) e.preventDefault();
              }}
            />
          </div>` : nothing}

        <div class="options-wrapper">
          ${this._renderOptions()}
        </div>
      </div>`;
  }

  static override styles = [styles];
}

declare global {
  interface HTMLElementTagNameMap { 'uwc-dropdown': UwcDropdown; }
}
