import { LitElement, html, nothing, type TemplateResult, type CSSResultGroup } from 'lit';
import styles from './styles.js';
import { classMap } from 'lit/directives/class-map.js';
import { repeat } from 'lit/directives/repeat.js';
import { live } from 'lit/directives/live.js';
import { property, state } from 'lit/decorators.js';
import type { MenuItem } from '../types.js';
import { emit } from '../utils/dom.utils.js';

// ══════════════════════════════════════════════════════════════════════════════
// TYPES & INTERFACES
// ══════════════════════════════════════════════════════════════════════════════

export type FilterType = 'text' | 'select' | 'date' | 'number';
export type ColumnType = 'text' | 'badge' | 'currency' | 'date' | 'rating' | 'avatar';
export type SelectionMode = 'none' | 'single' | 'multiple';

export interface ColumnDef {
  field: string;
  header: string;
  type?: ColumnType;
  sortable?: boolean;
  filterable?: boolean;
  filterType?: FilterType;
  filterOptions?: Array<{ label: string; value: string }>;
  width?: number;
  editable?: boolean;
}

export interface SortMeta {
  field: string;
  order: 1 | -1;
}

export interface FilterEntry {
  type: FilterType;
  value?: string;
  iso?: string;
  dateObj?: Date | null;
  min?: string | number;
  max?: string | number;
}

export interface EditingCell {
  key: unknown;
  field: string;
}

// Date helpers (used inside UwcDatatable for filter/cell rendering)
export const MNAMES = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'] as const;
export const DNAMES = ['Su','Mo','Tu','We','Th','Fr','Sa'] as const;

interface CalCell { d: Date; o: boolean; }

function buildGrid(year: number, month: number): CalCell[] {
  const fd = new Date(year, month, 1).getDay();
  const dm = new Date(year, month + 1, 0).getDate();
  const dp = new Date(year, month, 0).getDate();
  const cells: CalCell[] = [];
  for (let i = fd - 1; i >= 0; i--) cells.push({ d: new Date(year, month - 1, dp - i), o: true });
  for (let i = 1; i <= dm; i++)     cells.push({ d: new Date(year, month, i),           o: false });
  let n = 1;
  while (cells.length < 42)         cells.push({ d: new Date(year, month + 1, n++),     o: true });
  return cells;
}

function sameDay(a: Date | null | undefined, b: Date | null | undefined): boolean {
  return !!(a && b &&
    a.getFullYear() === b.getFullYear() &&
    a.getMonth()    === b.getMonth()    &&
    a.getDate()     === b.getDate());
}

export function fmtDate(d: Date | null | undefined): string {
  return d
    ? `${String(d.getMonth() + 1).padStart(2, '0')}/${String(d.getDate()).padStart(2, '0')}/${d.getFullYear()}`
    : '';
}

export function fmtISO(d: Date | null | undefined): string {
  return d
    ? `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`
    : '';
}

// Color maps (used inside _renderCell — override via subclassing if needed)
export const DEPT_COLORS: Record<string, string> = {
  Engineering: '#3b82f6', Marketing: '#f59e0b', Sales:       '#10b981',
  HR:          '#8b5cf6', Finance:   '#06b6d4', Design:      '#ec4899',
  Operations:  '#6b7280',
};

export const STATUS_COLORS: Record<string, string> = {
  Active: '#22c55e', 'On Leave': '#f59e0b', Inactive: '#ef4444',
};

// ══════════════════════════════════════════════════════════════════════════════
// uwc-datatable
// ══════════════════════════════════════════════════════════════════════════════

export class UwcDatatable extends LitElement {

  // ── Public properties ────────────────────────────────────────────────────

  @property({ attribute: false })
  data: Record<string, unknown>[] = [];

  @property({ attribute: false })
  columns: ColumnDef[] = [];

  @property({ type: String, attribute: 'selection-mode' })
  selectionMode: SelectionMode = 'multiple';

  @property({ type: String, attribute: 'row-key' })
  rowKey = 'id';

  @property({ type: Boolean, reflect: true })
  loading = false;

  @property({ type: Number })
  rows = 20;

  @property({ attribute: false })
  rowsPerPageOptions: number[] = [10, 20, 50, 100];

  @property({ type: String, attribute: 'scroll-height' })
  scrollableHeight: string = '520px';

  @property({ type: Boolean, attribute: 'row-expandable' })
  rowExpandable = false;

  @property({ type: Boolean, attribute: 'striped-rows' })
  stripedRows = true;

  @property({ type: Boolean, attribute: 'resizable-columns' })
  resizableColumns = true;

  @property({ type: String, attribute: 'state-storage' })
  stateStorage = '';

  @property({ type: String, attribute: 'empty-message' })
  emptyMessage = 'No records found.';

  // ── Internal reactive state ──────────────────────────────────────────────

  @state() private _page         = 1;
  @state() _pageSize              = 20;  // intentionally not private — settable from outside (demo)
  @state() private _sortMeta: SortMeta[] = [];
  @state() private _filters: Record<string, FilterEntry | null> = {};
  @state() private _globalFilter  = '';
  @state() private _selectedKeys  = new Set<unknown>();
  @state() private _expandedKeys  = new Set<unknown>();
  @state() private _showFilters   = false;
  @state() private _colWidths: Record<string, number> = {};
  @state() private _editingCell: EditingCell | null = null;
  @state() private _hiddenCols    = new Set<string>();
  @state() _colPanelOpen          = false;  // intentionally not private — settable from outside (demo)
  @state() private _resizingCol: string | null = null;
  @state() private _resizeStartX  = 0;
  @state() private _resizeStartW  = 0;

  // Resize handlers — pre-bound
  private readonly _onMouseMove: (e: MouseEvent) => void;
  private readonly _onMouseUp: () => void;

  constructor() {
    super();
    this._onMouseMove = this._onResizeMouseMove.bind(this);
    this._onMouseUp   = this._onResizeMouseUp.bind(this);
  }

  // ── Computed data ────────────────────────────────────────────────────────

  private get _filteredData(): Record<string, unknown>[] {
    let rows = this.data;

    // Global filter
    if (this._globalFilter.trim()) {
      const q = this._globalFilter.toLowerCase();
      rows = rows.filter(row =>
        Object.values(row).some(v => String(v).toLowerCase().includes(q))
      );
    }

    // Column filters
    for (const [field, f] of Object.entries(this._filters)) {
      if (!f) continue;
      rows = rows.filter(row => {
        const v = row[field];
        if (f.type === 'text') {
          return !f.value || String(v).toLowerCase().includes(f.value.toLowerCase());
        }
        if (f.type === 'select') {
          return !f.value || v === f.value;
        }
        if (f.type === 'date') {
          if (!f.iso) return true;
          return fmtISO(v as Date) === f.iso;
        }
        if (f.type === 'number') {
          const num = Number(v);
          if (f.min !== '' && f.min !== undefined && num < Number(f.min)) return false;
          if (f.max !== '' && f.max !== undefined && num > Number(f.max)) return false;
          return true;
        }
        return true;
      });
    }
    return rows;
  }

  private get _sortedData(): Record<string, unknown>[] {
    if (!this._sortMeta.length) return this._filteredData;
    return [...this._filteredData].sort((a, b) => {
      for (const { field, order } of this._sortMeta) {
        const av = a[field], bv = b[field];
        let cmp = 0;
        if (av instanceof Date && bv instanceof Date) {
          cmp = av.getTime() - bv.getTime();
        } else if (typeof av === 'number' && typeof bv === 'number') {
          cmp = av - bv;
        } else {
          cmp = String(av ?? '').localeCompare(String(bv ?? ''));
        }
        if (cmp !== 0) return cmp * order;
      }
      return 0;
    });
  }

  private get _pagedData(): Record<string, unknown>[] {
    const start = (this._page - 1) * this._pageSize;
    return this._sortedData.slice(start, start + this._pageSize);
  }

  private get _totalRecords(): number { return this._filteredData.length; }
  private get _totalPages():   number { return Math.max(1, Math.ceil(this._totalRecords / this._pageSize)); }

  private get _visibleColumns(): ColumnDef[] {
    return this.columns.filter(c => !this._hiddenCols.has(c.field));
  }

  private get _allSelected(): boolean {
    const paged = this._pagedData;
    return paged.length > 0 && paged.every(r => this._selectedKeys.has(r[this.rowKey]));
  }

  // ── Sort ──────────────────────────────────────────────────────────────────

  private _sort(field: string, e: MouseEvent): void {
    if (e.shiftKey) {
      // Multi-sort
      const existing = this._sortMeta.find(s => s.field === field);
      if (existing) {
        if (existing.order === 1) {
          this._sortMeta = this._sortMeta.map(s => s.field === field ? { ...s, order: -1 as const } : s);
        } else {
          this._sortMeta = this._sortMeta.filter(s => s.field !== field);
        }
      } else {
        this._sortMeta = [...this._sortMeta, { field, order: 1 }];
      }
    } else {
      // Single sort
      const cur = this._sortMeta.find(s => s.field === field);
      if (cur && this._sortMeta.length === 1) {
        this._sortMeta = cur.order === 1 ? [{ field, order: -1 }] : [];
      } else {
        this._sortMeta = [{ field, order: 1 }];
      }
    }
    this._page = 1;
  }

  private _getSortOrder(field: string): 0 | 1 | -1 {
    return (this._sortMeta.find(s => s.field === field)?.order ?? 0) as 0 | 1 | -1;
  }

  private _getSortRank(field: string): number {
    const idx = this._sortMeta.findIndex(s => s.field === field);
    return this._sortMeta.length > 1 ? (idx >= 0 ? idx + 1 : 0) : 0;
  }

  // ── Filter ────────────────────────────────────────────────────────────────

  private _setFilter(field: string, type: FilterType, patch: Partial<FilterEntry>): void {
    const cur = this._filters[field] ?? { type };
    this._filters = { ...this._filters, [field]: { ...cur, type, ...patch } };
    this._page = 1;
    emit(this, 'uwc-filter', { field, filters: this._filters });
  }

  private _clearAllFilters(): void {
    this._filters      = {};
    this._globalFilter = '';
    this._page         = 1;
  }

  private get _hasActiveFilters(): boolean {
    if (this._globalFilter.trim()) return true;
    return Object.values(this._filters).some(f => {
      if (!f) return false;
      if (f.type === 'number') return (f.min !== '' && f.min !== undefined) || (f.max !== '' && f.max !== undefined);
      return f.value || f.iso;
    });
  }

  // ── Selection ─────────────────────────────────────────────────────────────

  private _toggleRow(row: Record<string, unknown>, _e: Event): void {
    if (this.selectionMode === 'none') return;
    const key  = row[this.rowKey];
    const next = new Set(this._selectedKeys);
    if (this.selectionMode === 'single') {
      next.clear();
      if (!this._selectedKeys.has(key)) next.add(key);
    } else {
      next.has(key) ? next.delete(key) : next.add(key);
    }
    this._selectedKeys = next;
    emit(this, 'uwc-selection-change', {
      selectedKeys: [...this._selectedKeys],
      selectedRows: this.data.filter(r => this._selectedKeys.has(r[this.rowKey])),
    });
  }

  private _toggleAll(): void {
    if (this._allSelected) {
      const next = new Set(this._selectedKeys);
      this._pagedData.forEach(r => next.delete(r[this.rowKey]));
      this._selectedKeys = next;
    } else {
      const next = new Set(this._selectedKeys);
      this._pagedData.forEach(r => next.add(r[this.rowKey]));
      this._selectedKeys = next;
    }
    emit(this, 'uwc-selection-change', {
      selectedKeys: [...this._selectedKeys],
      selectedRows: this.data.filter(r => this._selectedKeys.has(r[this.rowKey])),
    });
  }

  // ── Expansion ─────────────────────────────────────────────────────────────

  private _toggleExpand(row: Record<string, unknown>, e: Event): void {
    e.stopPropagation();
    const key  = row[this.rowKey];
    const next = new Set(this._expandedKeys);
    next.has(key) ? next.delete(key) : next.add(key);
    this._expandedKeys = next;
  }

  // ── Inline edit ───────────────────────────────────────────────────────────

  private _startEdit(row: Record<string, unknown>, field: string, e: MouseEvent): void {
    if (e.detail !== 2) return; // double-click guard
    this._editingCell = { key: row[this.rowKey], field };
  }

  private _commitEdit(row: Record<string, unknown>, field: string, e: Event): void {
    const val  = (e.target as HTMLInputElement).value;
    const col  = this.columns.find(c => c.field === field);
    let parsed: unknown = val;
    if (col?.type === 'currency' || col?.type === 'rating') {
      parsed = Number(val.replace(/[^0-9.-]/g, '')) || 0;
    }
    // Mutate demo data (in real usage emit event and let parent update)
    const idx = this.data.findIndex(r => r[this.rowKey] === row[this.rowKey]);
    if (idx >= 0) {
      const copy = [...this.data];
      copy[idx] = { ...copy[idx], [field]: parsed };
      this.data = copy;
    }
    this._editingCell = null;
    emit(this, 'uwc-cell-edit', { row, field, value: parsed });
  }

  private _cancelEdit(): void { this._editingCell = null; }

  // ── Column resize ─────────────────────────────────────────────────────────

  private _startResize(field: string, e: MouseEvent): void {
    e.preventDefault(); e.stopPropagation();
    this._resizingCol  = field;
    this._resizeStartX = e.clientX;
    this._resizeStartW = this._colWidths[field] ?? (this.columns.find(c => c.field === field)?.width ?? 160);
    window.addEventListener('mousemove', this._onMouseMove);
    window.addEventListener('mouseup',   this._onMouseUp);
  }

  private _onResizeMouseMove(e: MouseEvent): void {
    if (!this._resizingCol) return;
    const delta = e.clientX - this._resizeStartX;
    const newW  = Math.max(80, this._resizeStartW + delta);
    this._colWidths = { ...this._colWidths, [this._resizingCol]: newW };
  }

  private _onResizeMouseUp(): void {
    window.removeEventListener('mousemove', this._onMouseMove);
    window.removeEventListener('mouseup',   this._onMouseUp);
    this._resizingCol = null;
  }

  // ── Export ────────────────────────────────────────────────────────────────

  private _exportCSV(): void {
    const cols   = this._visibleColumns;
    const header = cols.map(c => `"${c.header}"`).join(',');
    const rows   = this._sortedData.map(row =>
      cols.map(c => {
        let v = row[c.field];
        if (v instanceof Date) v = fmtDate(v);
        return `"${String(v ?? '').replace(/"/g, '""')}"`;
      }).join(',')
    );
    const csv  = [header, ...rows].join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement('a');
    a.href = url; a.download = 'datatable-export.csv'; a.click();
    URL.revokeObjectURL(url);
    emit(this, 'uwc-export', { format: 'csv', rowCount: this._sortedData.length });
  }

  // ── Pagination ────────────────────────────────────────────────────────────

  private _onPageChange(e: CustomEvent<{ first: number; rows: number; page: number; pageCount: number }>): void {
    this._page     = e.detail.page + 1; // paginator is 0-based, datatable is 1-based
    this._pageSize = e.detail.rows;
    emit(this, 'uwc-page', { page: this._page, pageSize: this._pageSize });
  }

  // ── Render ────────────────────────────────────────────────────────────────

  override render(): TemplateResult {
    return html`
      ${this._renderToolbar()}
      <div class="dt-wrapper">
        ${this.loading ? this._renderLoading() : nothing}
        <div class="dt-scroll" style="max-height:${this.scrollableHeight}">
          <table class="dt-table">
            <thead class="dt-head">
              ${this._renderHeaderRow()}
              ${this._showFilters ? this._renderFilterRow() : nothing}
            </thead>
            <tbody class="dt-body">
              ${this._pagedData.length === 0
                ? this._renderEmpty()
                : repeat(this._pagedData, r => r[this.rowKey], r => this._renderRow(r))
              }
            </tbody>
          </table>
        </div>
      </div>
      ${this._renderPagination()}
    `;
  }

  // ── Toolbar ───────────────────────────────────────────────────────────────

  private _renderToolbar(): TemplateResult {
    const selCount = this._selectedKeys.size;
    return html`
      <div class="dt-toolbar">
        <div class="dt-toolbar-left">
          <div class="dt-search-wrap">
            <svg class="dt-search-icon" width="14" height="14" viewBox="0 0 14 14" fill="none">
              <circle cx="5.5" cy="5.5" r="4.5" stroke="currentColor" stroke-width="1.3"/>
              <path d="M9 9l3.5 3.5" stroke="currentColor" stroke-width="1.3" stroke-linecap="round"/>
            </svg>
            <input
              class="dt-search"
              type="text"
              placeholder="Global search…"
              .value=${live(this._globalFilter)}
              @input=${(e: InputEvent) => { this._globalFilter = (e.target as HTMLInputElement).value; this._page = 1; }}
            />
            ${this._globalFilter
              ? html`<button class="dt-search-clr" @click=${() => { this._globalFilter = ''; this._page = 1; }}>×</button>`
              : nothing}
          </div>

          ${this._hasActiveFilters ? html`
            <button class="dt-toolbar-btn dt-active-filter" @click=${this._clearAllFilters.bind(this)}>
              <span>✕ Clear filters</span>
            </button>
          ` : nothing}

          ${selCount > 0 ? html`
            <div class="dt-sel-badge">${selCount} selected</div>
          ` : nothing}
        </div>

        <div class="dt-toolbar-right">
          <button class="dt-toolbar-btn ${this._showFilters ? 'active' : ''}"
            @click=${() => this._showFilters = !this._showFilters}>
            <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
              <path d="M1 3h12M3 7h8M5 11h4" stroke="currentColor" stroke-width="1.4" stroke-linecap="round"/>
            </svg>
            Filters
          </button>

          ${this._renderColVisibility()}

          <button class="dt-toolbar-btn" @click=${this._exportCSV.bind(this)}>
            <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
              <path d="M7 1v8M4 6l3 3 3-3M1 10v2a1 1 0 001 1h10a1 1 0 001-1v-2" stroke="currentColor" stroke-width="1.3" stroke-linecap="round" stroke-linejoin="round"/>
            </svg>
            Export CSV
          </button>
        </div>
      </div>
    `;
  }

  private _renderColVisibility(): TemplateResult {
    const cols = this.columns;
    return html`
      <div class="dt-col-vis-wrap">
        <button class="dt-toolbar-btn" id="col-vis-trigger"
          @click=${() => this._colPanelOpen = !this._colPanelOpen}>
          <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
            <rect x="1" y="1" width="5" height="12" rx="1" stroke="currentColor" stroke-width="1.2" fill="none"/>
            <rect x="8" y="1" width="5" height="12" rx="1" stroke="currentColor" stroke-width="1.2" fill="none"/>
          </svg>
          Columns
        </button>
        ${this._colPanelOpen ? html`
          <div class="dt-col-panel" @click=${(e: Event) => e.stopPropagation()}>
            <div class="dt-col-panel-hdr">
              <span>Show / hide columns</span>
              <button class="dt-col-close" @click=${() => this._colPanelOpen = false}>×</button>
            </div>
            ${cols.map(c => html`
              <label class="dt-col-item">
                <input type="checkbox"
                  .checked=${!this._hiddenCols.has(c.field)}
                  @change=${(e: Event) => {
                    const n = new Set(this._hiddenCols);
                    (e.target as HTMLInputElement).checked ? n.delete(c.field) : n.add(c.field);
                    this._hiddenCols = n;
                  }}
                />
                ${c.header}
              </label>
            `)}
          </div>
        ` : nothing}
      </div>
    `;
  }

  // ── Header row ───────────────────────────────────────────────────────────

  private _renderHeaderRow(): TemplateResult {
    const cols = this._visibleColumns;
    return html`
      <tr>
        ${this.selectionMode === 'multiple' ? html`
          <th class="dt-th dt-th-check" style="width:40px">
            <input type="checkbox"
              .checked=${this._allSelected}
              .indeterminate=${!this._allSelected && this._selectedKeys.size > 0}
              @change=${this._toggleAll.bind(this)}
            />
          </th>
        ` : nothing}
        ${this.rowExpandable ? html`<th class="dt-th" style="width:40px"></th>` : nothing}
        ${cols.map(col => {
          const sortOrder = this._getSortOrder(col.field);
          const sortRank  = this._getSortRank(col.field);
          const w         = this._colWidths[col.field] ?? col.width ?? 150;
          return html`
            <th class="dt-th ${col.sortable ? 'sortable' : ''} ${sortOrder ? 'sorted' : ''}"
              style="width:${w}px; min-width:${w}px"
              @click=${col.sortable ? (e: MouseEvent) => this._sort(col.field, e) : nothing}
            >
              <div class="dt-th-inner">
                <span class="dt-th-label">${col.header}</span>
                ${col.sortable ? html`
                  <span class="dt-sort-icon">
                    ${sortOrder === 1  ? html`<svg width="10" height="10" viewBox="0 0 10 10"><path d="M5 2l4 6H1z" fill="currentColor"/></svg>` : nothing}
                    ${sortOrder === -1 ? html`<svg width="10" height="10" viewBox="0 0 10 10"><path d="M5 8L1 2h8z" fill="currentColor"/></svg>` : nothing}
                    ${sortOrder === 0  ? html`<svg width="10" height="10" viewBox="0 0 10 10" style="opacity:.25"><path d="M5 2l3 4H2zM5 8l3-4H2z" fill="currentColor"/></svg>` : nothing}
                    ${sortRank > 0 ? html`<span class="dt-sort-rank">${sortRank}</span>` : nothing}
                  </span>
                ` : nothing}
              </div>
              ${this.resizableColumns ? html`
                <div class="dt-resize-handle" @mousedown=${(e: MouseEvent) => this._startResize(col.field, e)}></div>
              ` : nothing}
            </th>
          `;
        })}
        <th class="dt-th dt-th-actions" style="width:50px"></th>
      </tr>
    `;
  }

  // ── Filter row ───────────────────────────────────────────────────────────

  private _renderFilterRow(): TemplateResult {
    const cols = this._visibleColumns;
    return html`
      <tr class="dt-filter-row">
        ${this.selectionMode === 'multiple' ? html`<td class="dt-fc"></td>` : nothing}
        ${this.rowExpandable ? html`<td class="dt-fc"></td>` : nothing}
        ${cols.map(col => html`
          <td class="dt-fc">
            ${col.filterable !== false ? this._renderFilter(col) : nothing}
          </td>
        `)}
        <td class="dt-fc"></td>
      </tr>
    `;
  }

  private _renderFilter(col: ColumnDef): TemplateResult | typeof nothing {
    const f = this._filters[col.field];
    switch (col.filterType) {
      case 'select':
        return html`
          <uwc-dropdown
            .options=${(col.filterOptions ?? []).map(o => ({ label: o.label, value: o.value }))}
            .value=${f?.value ?? null}
            placeholder="All"
            placement="bottom-start"
            offset="2"
            show-clear
            @uwc-change=${(e: CustomEvent<{ value: unknown }>) =>
              this._setFilter(col.field, 'select', { value: String(e.detail.value ?? '') })}
            @uwc-clear=${() => this._setFilter(col.field, 'select', { value: '' })}
          ></uwc-dropdown>
        `;
      case 'date':
        return html`
          <uwc-datepicker
            .value=${f?.dateObj ?? null}
            placeholder="Select date"
            placement="bottom-start"
            offset="2"
            @uwc-date-select=${(e: CustomEvent<{ value: unknown }>) => {
              const d = e.detail.value as Date | null;
              const iso = d ? fmtISO(d) : '';
              this._setFilter(col.field, 'date', { value: iso, iso, dateObj: d });
            }}
            @uwc-clear=${() => this._setFilter(col.field, 'date', { value: '', iso: '', dateObj: null })}
          ></uwc-datepicker>
        `;
      case 'number':
        return html`
          <div class="dt-num-filter">
            <input type="number" placeholder="Min"
              .value=${live(String(f?.min ?? ''))}
              @input=${(e: InputEvent) => this._setFilter(col.field, 'number', { min: (e.target as HTMLInputElement).value })}
            />
            <input type="number" placeholder="Max"
              .value=${live(String(f?.max ?? ''))}
              @input=${(e: InputEvent) => this._setFilter(col.field, 'number', { max: (e.target as HTMLInputElement).value })}
            />
          </div>
        `;
      default:  // text
        return html`
          <div class="dt-text-filter">
            <input type="text" placeholder="Search…"
              .value=${live(f?.value ?? '')}
              @input=${(e: InputEvent) => this._setFilter(col.field, 'text', { value: (e.target as HTMLInputElement).value })}
            />
            ${f?.value
              ? html`<button class="dt-fc-clr" @click=${() => this._setFilter(col.field, 'text', { value: '' })}>×</button>`
              : nothing}
          </div>
        `;
    }
  }

  // ── Body rows ────────────────────────────────────────────────────────────

  private _renderRow(row: Record<string, unknown>): TemplateResult {
    const key      = row[this.rowKey];
    const selected = this._selectedKeys.has(key);
    const expanded = this._expandedKeys.has(key);
    const cols     = this._visibleColumns;

    return html`
      <tr
        class=${classMap({
          'dt-row':           true,
          'dt-row--selected': selected,
          'dt-row--expanded': expanded,
          'dt-row--stripe':   this.stripedRows,
        })}
        @click=${(e: MouseEvent) => this._toggleRow(row, e)}
      >
        ${this.selectionMode === 'multiple' ? html`
          <td class="dt-td dt-td-check" @click=${(e: Event) => e.stopPropagation()}>
            <input type="checkbox" .checked=${selected}
              @change=${(e: Event) => this._toggleRow(row, e)}/>
          </td>
        ` : nothing}

        ${this.rowExpandable ? html`
          <td class="dt-td dt-td-expand" @click=${(e: Event) => e.stopPropagation()}>
            <button class="dt-expand-btn ${expanded ? 'open' : ''}" type="button"
              @click=${(e: Event) => this._toggleExpand(row, e)}>
              ${expanded
                ? html`<svg width="10" height="10" viewBox="0 0 10 10"><path d="M2 3l3 4 3-4" stroke="currentColor" stroke-width="1.4" fill="none" stroke-linecap="round"/></svg>`
                : html`<svg width="10" height="10" viewBox="0 0 10 10"><path d="M3 2l4 3-4 3" stroke="currentColor" stroke-width="1.4" fill="none" stroke-linecap="round"/></svg>`
              }
            </button>
          </td>
        ` : nothing}

        ${cols.map(col => {
          const isEditing =
            this._editingCell?.key === key && this._editingCell?.field === col.field;
          return html`
            <td class="dt-td ${col.editable ? 'editable' : ''}"
              @click=${col.editable ? (e: MouseEvent) => this._startEdit(row, col.field, e) : nothing}
            >
              ${isEditing
                ? html`<input class="dt-inline-input" type="text"
                    .value=${live(String(row[col.field]))}
                    autofocus
                    @keydown=${(e: KeyboardEvent) => {
                      if (e.key === 'Enter')  this._commitEdit(row, col.field, e);
                      if (e.key === 'Escape') this._cancelEdit();
                    }}
                    @blur=${(e: Event) => this._commitEdit(row, col.field, e)}
                    @click=${(e: Event) => e.stopPropagation()}
                  />`
                : this._renderCell(row, col)
              }
            </td>
          `;
        })}

        <td class="dt-td dt-td-actions" @click=${(e: Event) => e.stopPropagation()}>
          <uwc-menu .items=${this._rowActions(row)} placement="bottom-end" offset="2">
            <uwc-button slot="trigger" icon="three-dots" icon-only variant="text" size="small" aria-label="Row actions"></uwc-button>
          </uwc-menu>
        </td>
      </tr>

      ${expanded ? html`
        <tr class="dt-row-expansion">
          <td
            colspan=${cols.length + (this.selectionMode === 'multiple' ? 1 : 0) + (this.rowExpandable ? 1 : 0) + 1}
            class="dt-expansion-cell"
          >
            ${this._renderExpansion(row)}
          </td>
        </tr>
      ` : nothing}
    `;
  }

  protected _renderCell(row: Record<string, unknown>, col: ColumnDef): TemplateResult {
    const v = row[col.field];
    switch (col.type) {
      case 'badge': {
        const color = col.field === 'department'
          ? DEPT_COLORS[v as string]
          : col.field === 'status'
          ? STATUS_COLORS[v as string]
          : '#888';
        return html`<span class="dt-badge" style="--bc:${color}">${v}</span>`;
      }
      case 'currency':
        return html`<span class="dt-currency">$${Number(v).toLocaleString()}</span>`;
      case 'date':
        return html`<span class="dt-date">${
          v instanceof Date
            ? v.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })
            : v
        }</span>`;
      case 'rating': {
        const n = Number(v);
        return html`<span class="dt-rating">
          ${Array.from({ length: 5 }, (_, i) => html`<span class="${i < n ? 'star-on' : 'star-off'}">★</span>`)}
        </span>`;
      }
      case 'avatar':
        return html`<div class="dt-avatar">${String(v).charAt(0).toUpperCase()}</div>`;
      default:
        return html`<span class="dt-text">${v}</span>`;
    }
  }

  private _rowActions(row: Record<string, unknown>): MenuItem[] {
    return [
      { icon: 'pencil-fill',  label: 'Edit',      command: () => emit(this, 'uwc-row-edit',      { row }) },
      { icon: 'copy',         label: 'Duplicate', command: () => emit(this, 'uwc-row-duplicate', { row }) },
      { icon: 'link-45deg',   label: 'Copy link', command: () => emit(this, 'uwc-row-link',      { row }) },
      { separator: true },
      { icon: 'trash-fill', label: 'Delete', danger: true, command: () => {
          this.data = this.data.filter(r => r[this.rowKey] !== row[this.rowKey]);
          this._selectedKeys.delete(row[this.rowKey]);
          this._selectedKeys = new Set(this._selectedKeys);
          emit(this, 'uwc-row-delete', { row });
        }
      },
    ];
  }

  protected _renderExpansion(row: Record<string, unknown>): TemplateResult {
    const salary     = row['salary'] as number;
    const startDate  = row['startDate'] as Date;
    const pct        = Math.min(100, Math.round(((salary - 50000) / 150000) * 100));
    const daysWorked = Math.round((Date.now() - startDate.getTime()) / 86_400_000);
    const rating     = row['rating'] as number;
    const status     = row['status'] as string;
    return html`
      <div class="dt-exp-card">
        <div class="dt-exp-avatar">${(row['name'] as string).charAt(0)}</div>
        <div class="dt-exp-info">
          <h3>${row['name']}</h3>
          <p class="dt-exp-role">${row['role']} · ${row['department']}</p>
          <div class="dt-exp-grid">
            <div><span class="dt-exp-lbl">Email</span><span>${row['email']}</span></div>
            <div><span class="dt-exp-lbl">Country</span><span>${row['country']}</span></div>
            <div><span class="dt-exp-lbl">Start Date</span><span>${fmtDate(startDate)}</span></div>
            <div><span class="dt-exp-lbl">Days Worked</span><span>${daysWorked.toLocaleString()} days</span></div>
            <div><span class="dt-exp-lbl">Status</span>
              <span class="dt-badge" style="--bc:${STATUS_COLORS[status]}">${status}</span>
            </div>
            <div><span class="dt-exp-lbl">Rating</span>
              <span class="dt-rating">
                ${Array.from({ length: 5 }, (_, i) => html`<span class="${i < rating ? 'star-on' : 'star-off'}">★</span>`)}
              </span>
            </div>
          </div>
          <div class="dt-exp-bar-wrap">
            <span class="dt-exp-lbl">Salary vs range ($50K–$200K)</span>
            <div class="dt-exp-bar"><div class="dt-exp-bar-fill" style="width:${pct}%"></div></div>
            <span class="dt-exp-bar-val">$${salary.toLocaleString()}</span>
          </div>
        </div>
      </div>
    `;
  }

  private _renderLoading(): TemplateResult {
    return html`
      <div class="dt-loading">
        <div class="dt-spinner"></div>
        <span>Loading…</span>
      </div>
    `;
  }

  private _renderEmpty(): TemplateResult {
    return html`
      <tr>
        <td colspan="999" class="dt-empty">
          <div class="dt-empty-inner">
            <svg width="40" height="40" viewBox="0 0 40 40" fill="none">
              <circle cx="20" cy="20" r="18" stroke="#e0ddd8" stroke-width="2"/>
              <path d="M13 20h14M20 13v14" stroke="#e0ddd8" stroke-width="2" stroke-linecap="round"/>
            </svg>
            <p>${this.emptyMessage}</p>
          </div>
        </td>
      </tr>
    `;
  }

  // ── Pagination ────────────────────────────────────────────────────────────

  private _renderPagination(): TemplateResult {
    const first = (this._page - 1) * this._pageSize;
    const rppOptions = this.rowsPerPageOptions.join(',');
    return html`
      <uwc-paginator
        total-records=${this._totalRecords}
        rows=${this._pageSize}
        first=${first}
        rows-per-page-options=${rppOptions}
        page-links="5"
        show-current-page-report
        current-page-report-template="Showing {first}–{last} of {totalRecords} records${this._totalRecords < this.data.length ? ` (filtered from ${this.data.length})` : ''}"
        @uwc-page-change=${this._onPageChange.bind(this)}
      ></uwc-paginator>
    `;
  }

  // ── Styles ────────────────────────────────────────────────────────────────

  static override styles = [styles];
}

// TypeScript module augmentation for custom events (optional, aids IDE completion)
declare global {
  interface HTMLElementTagNameMap {
    'uwc-datatable': UwcDatatable;
  }
  interface HTMLElementEventMap {
    'uwc-selection-change': CustomEvent<{ selectedKeys: unknown[]; selectedRows: Record<string, unknown>[] }>;
    'uwc-filter':           CustomEvent<{ field: string; filters: Record<string, FilterEntry | null> }>;
    'uwc-page':             CustomEvent<{ page: number; pageSize: number }>;
    'uwc-row-delete':       CustomEvent<{ row: Record<string, unknown> }>;
    'uwc-row-edit':         CustomEvent<{ row: Record<string, unknown> }>;
    'uwc-row-duplicate':    CustomEvent<{ row: Record<string, unknown> }>;
    'uwc-row-link':         CustomEvent<{ row: Record<string, unknown> }>;
    'uwc-cell-edit':        CustomEvent<{ row: Record<string, unknown>; field: string; value: unknown }>;
    'uwc-export':           CustomEvent<{ format: string; rowCount: number }>;
  }
}